//-------------------------------------------------------------------------
// 화면로딩시 - 웹스퀘어 기본
//-------------------------------------------------------------------------
scwin.onpageload = function() {
    scwin.userId = $c.data.getMemInfo($p, "userId") || "";
    scwin.empNo = $c.data.getMemInfo($p, "empNo") || "";
    scwin.p_lobranCd = $c.data.getMemInfo($p, "lobranCd") || " ";
    scwin.p_lobranNm = $c.data.getMemInfo($p, "lobranNm") || "";
    // TODO: 회사정보 조회용 submission 필요 (seaExgbIm, clntNo)
    scwin.p_seaExgbIm = scwin.p_seaExgbIm || "";
    scwin.p_clntNo = scwin.p_clntNo || "";

    scwin.p_linkcheck = $c.data.getParameter($p, "linkcheck") || "";
    scwin.p_kcomcd = $c.data.getParameter($p, "kcomcd") || "";
    scwin.p_blno = $c.data.getParameter($p, "blno") || "";
    scwin.p_mhno = $c.data.getParameter($p, "mhno") || "";
    scwin.p_bkno = $c.data.getParameter($p, "bkno") || "";
    scwin.p_no = $c.data.getParameter($p, "no") || "";
    scwin.p_row_cnt = $c.data.getParameter($p, "row_cnt") || "";
    scwin.p_data = $c.data.getParameter($p, "data") || "";
    scwin.p_hblno = $c.data.getParameter($p, "hblno") || "";
    scwin.p_docuno = $c.data.getParameter($p, "docuno") || "";

    var _strCurDate = $c.date.getServerDateTime();
    scwin.strPreDate = $c.date.addDate(_strCurDate, -2);
    scwin.strCurDate =  $c.date.getServerDateTime("yyyyMMdd");
    scwin.currentTime = $c.date.getServerDateTime("HHmm");

    scwin.v_linkcheck = scwin.p_linkcheck || "";
    scwin.v_kcomcd = scwin.p_kcomcd || "";
    scwin.v_blno = scwin.p_blno || "";
    scwin.v_mhno = scwin.p_mhno || "";
    scwin.v_bkno = scwin.p_bkno || "";
    scwin.tab_gb = scwin.tab_gb || "";
    scwin.popUpResult = scwin.popUpResult || null;
    scwin.gptYn = scwin.gptYn || false;
    scwin.temp_mhno = scwin.temp_mhno || null;
};

scwin.onUdcCompleted = function () {
    scwin.f_DefaultValue();
    const codeOptions = [
        {grpCd: "IL005", compID: "lc_hhincoterm"},
        {grpCd: "ZZ006", compID: "lc_shhcucd, lc_phhcucd, lc_bhhcucd"},    
    ];
    $c.data.setCommonCode(codeOptions);	    
	$c.util.setTimeout(
		function($p, ) {
            scwin.f_OnLoad ();
        },
		{ delay : 500, key : "loginTimeout" }
	);
};

scwin.f_OnLoad = function() {       
    scwin.f_initSetTab(); //tab세팅
    scwin.f_DefaultValue();
    scwin.f_Check();
    scwin.f_ContainerTypeLoading(); // Container Type 정보
    scwin.f_getParametrSetting(scwin.v_linkcheck); // link처리
    scwin.f_CurrencyLoading(); //환율 코드 정보. 
}

//---------------------------------------------------------
// Parameter Setting
//---------------------------------------------------------
scwin.f_getParametrSetting = function(gubun){
    switch ( gubun ) {
        case "0":
            break;

        case "1":  // Booking에서 Search Grid
            scwin.mhnoFlag = "1";

            if (scwin.v_blno == 'null'){
                cnd_ed_hhblno.setValue("");
                cnd_ed_hhblno.focus();
                return false;
            }

            scwin.hd_kcomcd = scwin.v_kcomcd;
            cnd_ed_hhblno.setValue(scwin.v_blno);

            if(ds_hmhno.getRowCount() == "0"){
                scwin._insertRow(ds_hmhno);
            }

            ds_hmhno.setCellData(ds_hmhno.getRowPosition(), "code", scwin.v_mhno);
            ds_hmhno.setCellData(ds_hmhno.getRowPosition(), "name", scwin.v_mhno);
            cnd_lc_mhno.focus();

        break;

        case "2":  // House Search
        scwin.mhnoFlag = "1";

            if (scwin.v_blno == 'null'){
                cnd_ed_hhblno.setValue("");
                cnd_ed_hhblno.focus();
                return false;
            }

            scwin.hd_kcomcd = scwin.v_kcomcd;
            cnd_ed_hhblno.setValue(scwin.v_blno);

            if(ds_hmhno.getRowCount() == "0"){
                scwin._insertRow(ds_hmhno);
            }

            ds_hmhno.setCellData(ds_hmhno.getRowPosition(), "code", scwin.v_mhno);
            ds_hmhno.setCellData(ds_hmhno.getRowPosition(), "name", scwin.v_mhno);
            cnd_lc_mhno.focus();

        break;

        case "4": 	// Booking 에서 h b/l버튼 (create)
            scwin.f_Create();
            ed_hhbkgno.setValue(scwin.v_bkno);
            cnd_ed_hhblno.focus(); //mhno를 보여주기위해서.
            tab_main.setSelectedTabIndex(0);  // 1번째 탭으로 이동.  cnd_ed_hhblno.focus() 잡아주기 위함.
            ed_hhbkgno.focus(); // 값 넣어주기 위해.
            ed_hheta.focus(); // etd값 반영.
            lc_hhbkgseq.focus();

            txt_blpic.setValue("");
            //기본으로 등록자 ID 기입 처리
            if (ed_blpic.getValue() == "") {
                ed_blpic.setValue(scwin.empNo);
                scwin.f_PopUp("B/L PIC", "T");
            }
        break;
    }
}
//---------------------------------------------------------
// Object Check
//---------------------------------------------------------
scwin.f_Check = function() {

    if(scwin.statusFlag == "I") {  
        cnd_lc_autono.setSelectedIndex(1);
        cnd_lc_mhno.setSelectedIndex(0);
        lc_hhbltype.setSelectedIndex(0);
        lc_hhpcgb.setSelectedIndex(1);
        lc_hhstype.setSelectedIndex(0);
        lc_hhcoload.setSelectedIndex(0);        

        ed_hhcnt1type.setValue("22GP");
        ed_hhcnt2type.setValue("42GP");
        ed_hhcnt3type.setValue("45GP");
        ed_hhcnt4type.setValue("42RE");
        ed_hhobl.setValue("3");
        ed_hhunitcd.setValue("GT");
        scwin.f_OpenCommonPopUp("Unit", "T", "F","F");

        chb_hhtriange.setValue("0");
        chb_hhnomi.setValue("0");

        rd_hhdanggb.setValue("N");
        rd_hhmnfgb.setValue("I");

        rd_hhcnrggb.setValue("C");
        rd_hhntrggb.setValue("C");

        lc_hhwaregb.setSelectedIndex(2);
        //ed_hhbuyer.setValue("scwin.p_lobranCd" );
        //txt_hhbuyernm.setValue("scwin.p_lobranNm" );

    }else if(scwin.statusFlag == "C") { // create?    
        cnd_lc_autono.setSelectedIndex(1);
        cnd_lc_mhno.setSelectedIndex(0);
        lc_hhbltype.setSelectedIndex(0);
        lc_hhpcgb.setSelectedIndex(1);
        lc_hhstype.setSelectedIndex(0);
        lc_hhcoload.setSelectedIndex(0);        

        ed_hhcnt1type.setValue("22GP");
        ed_hhcnt2type.setValue("42GP");
        ed_hhcnt3type.setValue("45GP");
        ed_hhcnt4type.setValue("42RE");
        ed_hhobl.setValue("3");

        ed_hhunitcd.setValue("GT");
        scwin.f_OpenCommonPopUp("Unit", "T", "F","F");

        chb_hhtriange.setValue("0");
        chb_hhnomi.setValue("0");

        rd_hhdanggb.setValue("N");
        rd_hhmnfgb.setValue("I");

        rd_hhcnrggb.setValue("C");
        rd_hhntrggb.setValue("C");

        lc_hhwaregb.setValue("C");
        //ed_hhbuyer.setValue("scwin.p_lobranCd" );
        //txt_hhbuyernm.setValue("scwin.p_lobranNm" );

        lc_shhcucd.setValue("USD"); // TODO: BindColVal
        lc_phhcucd.setValue("USD"); // TODO: BindColVal
        lc_bhhcucd.setValue("USD"); // TODO: BindColVal

        if (lc_hhbltype.getValue() != "B") { // TODO: BindColVal
            $c.gus.cfDisableObjects([ed_mtwgt]);//cargo type bulk??? M/T? ???
        }else{
            $c.gus.cfEnableObjects([ed_mtwgt]);
            $c.gus.cfDisableObjects([lc_hhbltype]);//?? ??? cargo type bulk??? cargo type ?? ???
        }
    }
}
//-------------------------------------------------------------------------
// 초기화
//-------------------------------------------------------------------------
scwin.f_DefaultValue = function() {
    scwin.f_setDSHeader( );

    scwin.f_Set("INIT");
    tab_main.setSelectedTabIndex(0);  // 1번째 탭으로 이동.  cnd_ed_hhblno.focus() 잡아주기 위함.
    cnd_ed_hhblno.focus();
}
//---------------------------------------------------------
// Tab 초기화
//---------------------------------------------------------
scwin.f_initSetTab = async function() {
    //$c.gus.cfEnableObjects([tr_tab_center0, tr_tab_center1, tr_tab_center2]);
    tab_main.setSelectedTabIndex(0);
}

//---------------------------------------------------------
// Tab Menu 선택시 처리
//---------------------------------------------------------
//---------------------------------------------------------
// Tab Menu ??? ??
//---------------------------------------------------------
scwin.f_selectTabMenu = async function(idx){
    switch( idx ) {
        case 0: //Main tab
        scwin.tab_gb = 0;
        break;

        case 1: //Other tab
        scwin.tab_gb = 1;
        break;
        case 2: //Other tab
        scwin.tab_gb = 2;
        break;
    }

    $c.gus.cfViewTab(idx);
    if(idx==1){
        buttonTable.style.top  = 538 + "px";
        buttonTable.style.display  = "block";
        scwin.f_divDefault();
    }else  if(idx==2){
        buttonTable.style.display  = "none";
    }else {
        buttonTable.style.top  = 538 + "px";
        buttonTable.style.display  = "block";
        scwin.f_divDefault();
    }
}
//---------------------------------------------------------
//화면세팅
//---------------------------------------------------------
scwin.f_Set = async function( gubun ) {    
    switch ( gubun ) {
        case "INIT" : //초기화
            $c.gus.cfDisableKeyData();  // Key와 Data를 모두 disable(non-editable) 상태로 변경한다.
            //scwin.f_setDisabledComp(true);
            $c.gus.cfDisableBtnOnly([btn_Copy,btn_FCopy, btn_Cancel, btn_Save, btn_Save_top, btn_Delete, btn_Update, btn_Update_top, btn_FSave, btn_FDelete, btn_FUpdate, btn_FCancel
            ,btn_1_N,btn_3,btn_4,btn_8,btn_10, btn_Upload
            ,btn_AddCntr, btn_AddCntr1, btn_DelRow2, grpBtn1, pu_departmentChange]);
            $c.gus.cfEnableBtnOnly([btn_Create,btn_Retrieve]);
            scwin.statusFlag = "I";
            break;
        case "RETRIEVE" :  //조회모드
            $c.gus.cfDisableKeyData();
            $c.gus.cfDisableBtnOnly([btn_Save, btn_Save_top, btn_Cancel, btn_AddCntr, btn_AddCntr1, btn_DelRow2, grpBtn1
            ,btn_FCancel,btn_FSave, grpBtn2, grpBtn3, grpBtn4, btn_FCopyRow3]);
            $c.gus.cfEnableBtnOnly([btn_Copy, btn_FCopy, btn_Create, btn_Delete,btn_FDelete,btn_Retrieve, btn_1_N
            ,btn_4,btn_8,btn_10,pu_departmentChange,btn_13,btn_14,btn_Hblchg, btn_Upload]);
            // 그리드 수정 못하게 한다.
            gr_ocContList.setReadOnly("grid", true);
            gr_selling.setReadOnly("grid", true);
            gr_partner.setReadOnly("grid", true);
            gr_buying.setReadOnly("grid", true);

            if (scwin.statusFlag == "C"){
                $c.gus.cfDisableBtnOnly([btn_Update, btn_Update_top, btn_FUpdate]);
            }else{
                $c.gus.cfEnableBtnOnly([btn_Update, btn_Update_top, btn_FUpdate]);
            }

            $c.gus.cfEnableObjects([cnd_ed_hhblno,cnd_lc_autono,cnd_lc_mhno,cnd_ed_hhmblno]); // 조회조건.
            scwin.statusFlag = "";	 // flag null
            break;

        case "CREATE" : //신규
            $c.gus.cfEnableKeyData();
            $c.gus.cfDisableBtnOnly([btn_Copy,btn_FCopy,btn_Create, btn_Update,btn_Update_top, btn_Retrieve, btn_Delete,btn_4,btn_8,btn_10,pu_departmentChange,btn_FUpdate,btn_FDelete ]);
            $c.gus.cfEnableBtnOnly([btn_Save, btn_Save_top, btn_Cancel ,btn_1,btn_1_N, btn_1_P,btn_1_B,btn_2,btn_2_P, btn_2_B, btn_3,btn_AddCntr, btn_AddCntr1,btn_FSave,btn_FCancel
            ,grpBtn1,grpBtn2,grpBtn3,grpBtn4, btn_FCopyRow3,pu_ResultdateChange , btn_Upload, btn_DelRow2]);
            // 그리드 수정 가능
            gr_ocContList.setReadOnly("grid", false);
            gr_selling.setReadOnly("grid", false);
            gr_partner.setReadOnly("grid", false);
            gr_buying.setReadOnly("grid", false);
            $c.gus.cfDisableObjects([cnd_ed_hhblno,cnd_lc_autono,cnd_lc_mhno,cnd_ed_hhmblno]); // 조회조건.
            $c.gus.cfEnableObjects([cnd_ed_hhblno,cnd_lc_autono]); // 조회조건.
            scwin.statusFlag = "C";
            break;

        case "UPDATE" :
            $c.gus.cfDisableBtnOnly([btn_Copy, btn_FCopy, btn_Update, btn_Update_top, btn_Create,btn_Retrieve, btn_Delete,btn_4,btn_8,btn_10,btn_FUpdate,btn_FDelete,btn_Hblchg, pu_departmentChange]);
            $c.gus.cfEnableBtnOnly([btn_Save, btn_Save_top, btn_Cancel, btn_AddCntr, btn_AddCntr1
            ,btn_FSave,btn_FCancel,grpBtn1, grpBtn2,grpBtn3,grpBtn4, btn_FCopyRow3,pu_ResultdateChange, btn_Upload, btn_DelRow2]);
            $c.gus.cfDisableKey();
            // 그리드 수정 가능
            gr_ocContList.setReadOnly("grid", false);
            gr_selling.setReadOnly("grid", false);
            gr_partner.setReadOnly("grid", false);
            gr_buying.setReadOnly("grid", false);
            $c.gus.cfDisableObjects([cnd_ed_hhblno,cnd_lc_autono,cnd_lc_mhno,cnd_ed_hhmblno,ed_hhbkgno,lc_hhbkgseq]); // 조회조건,booking no
            scwin.statusFlag = "U";
            break;

        case "SAVE" :
            $c.gus.cfDisableBtnOnly([btn_Save, btn_Save_top, btn_Delete, btn_Cancel,btn_FSave,btn_FDelete,btn_FCancel]);
            $c.gus.cfEnableBtnOnly([btn_Update, btn_Update_top, btn_Create,btn_FUpdate]);
            scwin.f_Set("RETRIEVE");

            break;
    }
}
//---------------------------------------------------------
// function name : scwin.f_setDSHeader
// function desc : Grid Header정보 Setting
//---------------------------------------------------------
scwin.f_setDSHeader = async function(  ){
    scwin._clearDataMap(dma_retrieve);
    scwin._clearDataMap(dma_bookingNo);
    scwin._clearDataMap(dma_bookingContainer);

    scwin._clearDataMap(dma_retrieveBooking);

    scwin._clearDataMap(dma_retrieveCtrtClnt);
    scwin._insertRow(ds_retrieveMhNo);
    scwin._clearDataMap(dma_retrieveMbl);
}
//---------------------------------------------------------
// 조회
//---------------------------------------------------------

scwin.f_Retrieve = async function() {

    if ($c.util.isEmpty(cnd_ed_hhblno.getValue())) {
        $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["House No"]);
        return;
    }
    cnd_lc_mhno.focus(); // B/L No 빠져나올때 event처리 .
    dma_retrieve.set("kcomcd", scwin.hd_kcomcd);
    dma_retrieve.set("hhblno", cnd_ed_hhblno.getValue());
    dma_retrieve.set("mhno", cnd_lc_mhno.getValue());
    dma_retrieve.set("hhio", scwin.hd_hhio);
    dma_retrieve.set("mhio", scwin.hd_hhio);

    //Booking Seq 넣어 주기.
    ds_bkseq.removeAll();
    scwin._insertRow(ds_bkseq);

    if (cnd_lc_autono.getValue() == "DIRECT") {
        await $c.sbm.execute(sbm_retrieveMhno);
        await $c.sbm.execute(sbm_retrieve);
    } else {
        await $c.sbm.execute(sbm_retrieve);
    }

    txt_blpic.setValue("");
    if (ed_blpic.getValue() != "") {
        scwin.f_PopUp("B/L PIC", "T");
    }

    gr_selling.setHeaderDisabled('chk', true);
    gr_partner.setHeaderDisabled('chk', true);
    gr_buying.setHeaderDisabled('chk', true);
}
//---------------------------------------------------------
// 조회(하단)
//---------------------------------------------------------

scwin.f_Retrieve2 = async function() {    
    //상단을 조회하지 않았거나, 결과값이 없을 경우
    if (ds_houseblList.getRowCount() < 1) {
        $c.gus.cfAlertMsg(E_MSG_CM_WRN_018, ["Exchange Rate Information","상단의 Search"]);  // @이(가) 존재하지 않습니다.\n먼저 @을(를) 하십시오.
        return;
    }

    if (srch_ed_hhblno.getValue().trim() == "") {
        $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["House No"]);  // @은(는) 필수 입력 항목입니다.
        return;
    }

    if (ds_sellingUnit.getRowCount() == 0) await scwin.f_allUnitLoading();

    cnd_lc_mhno2.focus(); // B/L No 빠져나올때 event처리 .
    dma_retrieve.set("kcomcd", scwin.hd_kcomcd);
    dma_retrieve.set("mhno", cnd_lc_mhno2.getValue());
    dma_retrieve.set("hhio", scwin.hd_hhio);
    dma_retrieve.set("hhblno2", srch_ed_hhblno.getValue());
    //기존에 조회된 행이 있다면 재조회 안되도록함 개별검색은 재조회 가능
    if (ds_selling.getRowCount() > 0 && ds_selling.getCellData(ds_selling.getRowPosition(), "tabIndex") == "") {
        alert("조회된 Selling데이터가 있습니다.\nSelling데이터가 0건일 경우 조회가능합니다.");
    }else{
        $c.sbm.execute(sbm_retrieveSelling);
    }

    if (ds_partner.getRowCount() > 0 && ds_partner.getCellData(ds_partner.getRowPosition(), "tabIndex") == "") {
        alert("조회된 Partner데이터가 있습니다.\nPartner데이터가 0건일 경우 조회가능합니다.");
    }else{
        $c.sbm.execute(sbm_retrievePartner); 
    }

    if (ds_buying.getRowCount() > 0 && ds_buying.getCellData(ds_buying.getRowPosition(), "tabIndex") == "") {
        alert("조회된 Buying데이터가 있습니다.\nBuying데이터가 0건일 경우 조회가능합니다.");
    }else{
        $c.sbm.execute(sbm_retrieveBuying); 
        //dataSetDebug(ds_buying,true);
    }
    //cmd anable
    $c.gus.cfEnableObj(srch_ed_hhblno, true);
    $c.gus.cfEnableObj(cnd_lc_mhno2, true);
}

scwin.f_allUnitLoading = async function (forceLoad) {
    var cnt = scwin._getCntParams();
    var key = cnt.join(",");

    if (!forceLoad && scwin._lastUnitParams === key && ds_sellingUnit.getRowCount() > 0) return;
    scwin._lastUnitParams = key;
    var gauce = await scwin.f_commCodeSync("SeaImportHouseEBC", "retriveUnitList", cnt[0], cnt[1], cnt[2], cnt[3]);
    ds_sellingUnit.removeAll();
    ds_partnerUnit.removeAll();
    ds_buyingUnit.removeAll();
    if (gauce) {
        ds_sellingUnit.setJSON(gauce);
        ds_partnerUnit.setJSON(gauce);
        ds_buyingUnit.setJSON(gauce);
    }    
};

//---------------------------------------------------------
// 조회 조건 지우기
//---------------------------------------------------------
scwin.f_FieldClear = async function()  {
    $c.gus.cfInitObjects([cnd_ed_hhblno, cnd_ed_hhmblno]);
    //cnd_lc_autono.setIndex(1); //입력 COMBO // TODO: index api
    ds_hmhno.removeAll(); // DATASET COMBO
}

//---------------------------------------------------------
// 조회 조건 지우기
//---------------------------------------------------------
scwin.f_FieldClear2 = async function()  {
    $c.gus.cfInitObjects([srch_ed_hhblno]);
    ds_hmhno2.removeAll(); // DATASET COMBO
