//-------------------------------------------------------------------------
scwin.f_Update = async function() {
    if (scwin.statusFlag != "C" && ed_hheta.getValue() == "") {  // 등록 화면에 필수인 ETD를 기준으로 잡았음.
        $c.gus.cfAlertMsg(E_MSG_CM_ERR_003); //  해당되는 자료가 존재하지 않습니다
        return;
    }else{
        scwin.f_Set("UPDATE");

        // invoice check
        scwin.f_invoiceCheck(); // invoice Check
        $c.gus.cfDisableObjects([ed_hhbuyer, txt_hhbuyernm, img_PopUp15]);

        if (lc_shhcucd.getValue() == "") lc_shhcucd.setValue("USD");
        if (ed_shhcurdt.getValue() == "") ed_shhcurdt.setValue(ed_hheta.getValue());

        if (lc_phhcucd.getValue() == "") lc_phhcucd.setValue("USD");
        if (ed_phhcurdt.getValue() == "") ed_phhcurdt.setValue(ed_hheta.getValue());

        if (lc_bhhcucd.getValue() == "") lc_bhhcucd.setValue("USD");
        if (ed_bhhcurdt.getValue() == "") ed_bhhcurdt.setValue(ed_hheta.getValue());

        if (lc_hhbltype.getValue() != "B") {
            $c.gus.cfDisableObjects([ed_mtwgt]);//cargo type bulk일때만 M/T칸 활성화
        }else{
            $c.gus.cfEnableObjects([ed_mtwgt]);
            $c.gus.cfDisableObjects([lc_hhbltype]);//처음 생성한 cargo type bulk일때는 cargo type 변경 못하게
        }
    }
}

//-------------------------------------------------------------------------
// Dataset DEBUG
//-------------------------------------------------------------------------
scwin.dataSetDebug = async function(dataSet, isDebug) {
    if (isDebug == true) {
        var obj = dataSet;
        var str = "[[[[" + (obj.id || "") + "]]]]" + "\n";
        var rowCount = obj.getRowCount ? obj.getRowCount() : 0;
        var colIds = obj.getColumnIds ? obj.getColumnIds() : [];
        for (var r = 0; r < rowCount; r++) {
            for (var c = 0; c < colIds.length; c++) {
                var colId = colIds[c];
                str += "[" + colId + "] " + Number(obj.getCellData(r, colId)) + ", ";
            }
            str += "\n\n";
        }
        alert(str);
    }
}

//-------------------------------------------------------------------------
// Hidden/Display None Binding Sync
//-------------------------------------------------------------------------
scwin._syncHiddenAfterRetrieve = function() {    
    if (ds_houseblList.getRowCount() > 0) {
        var rowH = ds_houseblList.getRowPosition();
        if (rowH == null || rowH < 0) rowH = 0;
        scwin.hd_hhitem = ds_houseblList.getCellData(rowH, "hhitem") || scwin.hd_hhitem || "";
        scwin.hd_creadyDt = ds_houseblList.getCellData(rowH, "creadyDt") || scwin.hd_creadyDt || "";
        scwin.hd_hhpcgb = ds_houseblList.getCellData(rowH, "hhpcgb") || scwin.hd_hhpcgb || "";
        scwin.hd_hhdanggb = ds_houseblList.getCellData(rowH, "hhdanggb") || scwin.hd_hhdanggb || "";
    }
    if (ds_FreighthouseblList.getRowCount() > 0) {
        var row = ds_FreighthouseblList.getRowPosition();
        if (row == null || row < 0) row = 0;
        scwin.hd_hhitem = ds_FreighthouseblList.getCellData(row, "hhitem") || "";
        scwin.hd_creadyDt = ds_FreighthouseblList.getCellData(row, "creadyDt") || "";
        scwin.hd_hhpcgb = ds_FreighthouseblList.getCellData(row, "hhpcgb") || "";
        scwin.hd_hhdanggb = ds_FreighthouseblList.getCellData(row, "hhdanggb") || "";
    }
};

scwin._syncHiddenBeforeSave = function() {
    var rowH = ds_houseblList.getRowPosition();
    if (rowH == null || rowH < 0) rowH = 0;
    if (ds_houseblList.getRowCount() === 0) {
        ds_houseblList.insertRow(0);
    }
    ds_houseblList.setCellData(rowH, "hhitem", scwin.hd_hhitem || "");
    ds_houseblList.setCellData(rowH, "creadyDt", scwin.hd_creadyDt || "");
    ds_houseblList.setCellData(rowH, "hhpcgb", scwin.hd_hhpcgb || "");
    ds_houseblList.setCellData(rowH, "hhdanggb", scwin.hd_hhdanggb || "");
    var row = ds_FreighthouseblList.getRowPosition();
    if (row == null || row < 0) row = 0;
    if (ds_FreighthouseblList.getRowCount() === 0) {
        ds_FreighthouseblList.insertRow(0);
    }
    ds_FreighthouseblList.setCellData(row, "hhitem", scwin.hd_hhitem || "");
    ds_FreighthouseblList.setCellData(row, "creadyDt", scwin.hd_creadyDt || "");
    ds_FreighthouseblList.setCellData(row, "hhpcgb", scwin.hd_hhpcgb || "");
    ds_FreighthouseblList.setCellData(row, "hhdanggb", scwin.hd_hhdanggb || "");
};

//-------------------------------------------------------------------------
// 동부하이텍 필수항목 체크
//-------------------------------------------------------------------------
scwin.f_HiDataCheck = function() {
    if (ed_hheta.getValue() == "") {  //ETA
        $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Dongbu Hitek :ETA"]);  // @은(는) 필수 입력 항목입니다.
        ed_hheta.focus();
        return false;
    }

    if (ed_hhetd.getValue() == "") {  //ETD
        $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Dongbu Hitek : ETD"]);  // @은(는) 필수 입력 항목입니다.
        ed_hhetd.focus();
        return false;
    }

    if (ed_pickupdt.getValue() == "") {  //PICKUP
        $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Dongbu Hitek : PICKUP DATE"]);  // @은(는) 필수 입력 항목입니다.
        ed_pickupdt.focus();
        return false;
    }

    if (txt_hhpono.getValue() == "") {  // Purchase Order NO
        $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Dongbu Hitek : Purchase Order NO "]);  // @은(는) 필수 입력 항목입니다.
        $c.gus.cfViewTab(1);
        txt_hhpono.focus();
        return false;
    }

    if (ed_hhdisccd.getValue() == "") {
        $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Dongbu Hitek :  Discharge Code "]);  // @은(는) 필수 입력 항목입니다.
        ed_hhdisccd.focus();
        return false;
    }

    if (ed_hhlodcd.getValue() == "") {
        $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Dongbu Hitek : Loading Code "]);  // @은(는) 필수 입력 항목입니다.
        ed_hhlodcd.focus();
        return false;
    }

    return true;
}

