//---------------------------------------------------------
//행추가
//---------------------------------------------------------
scwin.f_addRow = function(disGubun) {
    switch (disGubun) {
        case 1: // Container
            if (cnd_ed_hhblno.getValue() == "") {
                $c.gus.cfAlertMsg(E_MSG_CM_ERR_003); //  해당되는 자료가 존재하지 않습니다
            }else{
                let nRowNum = ds_ocContList.insertRow(ds_ocContList.getRowCount());
                ds_ocContList.setCellData(nRowNum, "kcomcd", scwin.hd_kcomcd);
                ds_ocContList.setCellData(nRowNum, "mchblno", cnd_ed_hhblno.getValue());
                ds_ocContList.setCellData(nRowNum, "mhno", cnd_lc_mhno.getValue() || "");
                ds_ocContList.setCellData(nRowNum, "inpid", scwin.userId);

                ds_ocContList.setCellData(nRowNum, "mcpkgcd", ed_hhunitcd.getValue());

                gr_ocContList.setFocusedCell(nRowNum, "mccntno", true);
                break;            
            }
            break;

        default:
        break;
    }
}

//---------------------------------------------------------
// 행삭제
//---------------------------------------------------------
scwin.f_deleteRow = function(disGubun) {    
    switch (disGubun) {
        case 1: // Container
			if(ds_ocContList.getRowStatus(ds_ocContList.getRowPosition()) == "C"){
        		ds_ocContList.removeRow(ds_ocContList.getRowPosition());	
			}else{
        		ds_ocContList.deleteRow(ds_ocContList.getRowPosition());	
			}
            break;
        case 2:            
            $c.data.deleteRow(ds_ocContList);
            break;

        default:
        break;
    }
}

//---------------------------------------------------------
// 행취소
//---------------------------------------------------------
scwin.f_cancelRow = function(disGubun) {    
    switch (disGubun) {
        case 1: // Container             
            $c.data.undoAll(ds_ocContList);
            break;
        default:
            break;
    }
}

//---------------------------------------------------------
//Freight 행추가
//---------------------------------------------------------
scwin.f_FaddRow = async function(disGubun) {
    let row;
    switch (disGubun) {
        case 1: // Selling
            if ($c.util.isEmpty(cnd_ed_hhblno.getValue())) {
                $c.gus.cfAlertMsg(E_MSG_CM_ERR_003); //  해당되는 자료가 존재하지 않습니다
                return;
            }
            if (ds_selling.getRowCount() == 0 || ds_selling.getRowPosition() == ds_selling.getRowCount() - 1) {
                row = ds_selling.insertRow(ds_selling.getRowCount());
            } else {
                row = ds_selling.insertRow(ds_selling.getRowPosition() + 1);
            }

            ds_selling.setCellData(row, "kcomcd", scwin.hd_kcomcd);
            ds_selling.setCellData(row, "blNo", cnd_ed_hhblno.getValue());
            ds_selling.setCellData(row, "mhno", cnd_lc_mhno.getValue());
            ds_selling.setCellData(row, "odrNo", ds_houseblList.getCellData(0, "odrNo"));

            ds_selling.setCellData(row, "drcrCls", "D");
            ds_selling.setCellData(row, "locPtnCls", "1");
            ds_selling.setCellData(row, "mblHblCls", "H");
            ds_selling.setCellData(row, "seaAirCls", "S");
            ds_selling.setCellData(row, "ppccCls", ds_houseblList.getCellData(ds_houseblList.getRowPosition(), "hhpcgb"));
            ds_selling.setCellData(row, "inpid", scwin.userId);

            ds_selling.setCellData(row, "bilgClntNo", ed_hhactcust.getValue());
            ds_selling.setCellData(row, "bilgClntNm", txt_hhactcustnm.getValue());
            ds_selling.setCellData(row, "rsltsStdDt", scwin.hd_creadyDt);
            ds_selling.setCellData(row, "exRateTyp", lc_shhexgb.getValue());

            // unit/패키지 로딩
            if (ds_sellingUnit.getRowCount() == 0) await scwin.f_allUnitLoading();
            if (ds_sellingUnit.getRowCount() > 0) {
                ds_selling.setCellData(row, "fareUnit", ds_sellingUnit.getCellData(0, "code"));
            }
            await scwin.f_packageRateSellingLoading(row, "");

            gr_selling.focus();
            gr_selling.setFocusedCell(row, "bilgClntNo"); // focus

            if (ds_houseblList.getCellData(0, "hhbltype") == "L") {

                ds_selling.setCellData(row, "fareUnit", "R/T");
                await scwin.f_packageRateSellingLoading(row, '');

                gr_selling.focus();
                gr_selling.setFocusedCell(row, "bilgClntNo"); // focus
            }
            break;
        case 2: // Partner
            if ($c.util.isEmpty(cnd_ed_hhblno.getValue())) {
                $c.gus.cfAlertMsg(E_MSG_CM_ERR_003); //  해당되는 자료가 존재하지 않습니다
                return;
            }

            if (ds_partner.getRowCount() == 0 || ds_partner.getRowPosition() == ds_partner.getRowCount() - 1) {
                row = ds_partner.insertRow(ds_partner.getRowCount());
            } else {
                row = ds_partner.insertRow(ds_partner.getRowPosition() + 1);
            }

            ds_partner.setCellData(row, "kcomcd", scwin.hd_kcomcd);
            ds_partner.setCellData(row, "blNo", cnd_ed_hhblno.getValue());
            ds_partner.setCellData(row, "mhno", cnd_lc_mhno.getValue());
            ds_partner.setCellData(row, "odrNo", ds_houseblList.getCellData(0, "odrNo"));

            ds_partner.setCellData(row, "drcrCls", "C");
            ds_partner.setCellData(row, "locPtnCls", "2");
            ds_partner.setCellData(row, "mblHblCls", "H");
            ds_partner.setCellData(row, "seaAirCls", "S");
            ds_partner.setCellData(row, "inpid", scwin.userId);

            ds_partner.setCellData(row, "ppccCls", ds_houseblList.getCellData(ds_houseblList.getRowPosition(), "hhpcgb"));
            ds_partner.setCellData(row, "bilgClntNo", ed_hhagent.getValue());
            ds_partner.setCellData(row, "bilgClntNm", txt_hhagentnm.getValue());
            ds_partner.setCellData(row, "rsltsStdDt", scwin.hd_creadyDt);
            ds_partner.setCellData(row, "exRateTyp", lc_phhexgb.getValue());

            //unit처리.
            if (ds_partnerUnit.getRowCount() == 0) await scwin.f_allUnitLoading();
            if (ds_partnerUnit.getRowCount() > 0) {
                ds_partner.setCellData(row, "fareUnit", ds_partnerUnit.getCellData(0, "code"));
            }

            await scwin.f_packageRatePartnerLoading(row, "");

            gr_partner.focus();
            gr_partner.setFocusedCell(row, "bilgClntNo"); // focus

            break;
        case 3: // Buying
            if ($c.util.isEmpty(cnd_ed_hhblno.getValue())) {
                $c.gus.cfAlertMsg(E_MSG_CM_ERR_003); //  해당되는 자료가 존재하지 않습니다
                return;
            }

            if (ds_buying.getRowCount() == 0 || ds_buying.getRowPosition() == ds_buying.getRowCount() - 1) {
                row = ds_buying.insertRow(ds_buying.getRowCount());
            } else {
                row = ds_buying.insertRow(ds_buying.getRowPosition() + 1);
            }
            ds_buying.setCellData(row, "kcomcd", scwin.hd_kcomcd);
            ds_buying.setCellData(row, "blNo", cnd_ed_hhblno.getValue());
            ds_buying.setCellData(row, "mhno", cnd_lc_mhno.getValue());
            ds_buying.setCellData(row, "odrNo", ds_houseblList.getCellData(0, "odrNo"));

            ds_buying.setCellData(row, "drcrCls", "C");
            ds_buying.setCellData(row, "locPtnCls", "1");
            ds_buying.setCellData(row, "mblHblCls", "H");
            ds_buying.setCellData(row, "seaAirCls", "S");
            ds_buying.setCellData(row, "ppccCls", ds_houseblList.getCellData(ds_houseblList.getRowPosition(), "hhpcgb")); // hd_hhpcgb
            ds_buying.setCellData(row, "inpid", scwin.userId);

            ds_buying.setCellData(row, "pchsClntNo", ed_hhliner.getValue());
            ds_buying.setCellData(row, "pchsClntNm", txt_hhlinernm.getValue());
            ds_buying.setCellData(row, "rsltsStdDt", scwin.hd_creadyDt);
            ds_buying.setCellData(row, "exRateTyp", lc_bhhexgb.getValue());
            ds_buying.setCellData(row, "pchsTyp", "1");
            ds_buying.setCellData(row, "crcCd", ds_buying.getCellData(row - 1, "crcCd"));

            if (ds_buyingUnit.getRowCount() == 0) await scwin.f_allUnitLoading();
            if (ds_buyingUnit.getRowCount() > 0) {
                ds_buying.setCellData(row, "fareUnit", ds_buyingUnit.getCellData(0, "code"));
            }
            await scwin.f_packageRateBuyingLoading(row, "");

            gr_buying.focus();
            gr_buying.setFocusedCell(row, "pchsClntNo"); // focus

            if (ds_houseblList.getCellData(0, "hhbltype") == "L") {
                ds_buying.setCellData(row, "fareUnit", "R/T");
                await scwin.f_packageRateBuyingLoading(row, '');

                gr_buying.focus();
                gr_buying.setFocusedCell(row, "pchsClntNo"); // focus								
            }

            break;
    }
}

