            ds_partner.setCellData(row, "drcrCls", "C");
            ds_partner.setCellData(row, "locPtnCls", "2");
            ds_partner.setCellData(row, "mblHblCls", "H");
            ds_partner.setCellData(row, "seaAirCls", "S");
            ds_partner.setCellData(row, "ppccCls", scwin.hd_hhpcgb);
            ds_partner.setCellData(row, "inpid", scwin.userId);

            ds_partner.setCellData(row, "bilgClntNo", ed_hhagent.getValue());
            ds_partner.setCellData(row, "bilgClntNm", txt_hhagentnm.getValue());
            ds_partner.setCellData(row, "rsltsStdDt", scwin.hd_creadyDt);
            ds_partner.setCellData(row, "exRateTyp", lc_phhexgb.getValue());
            ds_partner.setCellData(row, "chgWt", "1");             

            await scwin.f_partnerUnitLoading();
            if (ds_partnerUnit.getRowCount() > 0) {
                ds_partner.setCellData(row, "fareUnit", ds_partnerUnit.getCellData(0, "code"));
            }
            scwin.f_packageRatePartnerLoading(row, "");

            gr_partner.focus();                
            gr_partner.setFocusedCell(row, "bilgClntNo");

            break;

        case 3: // Buying            
            if (cnd_ed_hhblno.getValue() == "") {
                $c.gus.cfAlertMsg(E_MSG_CM_ERR_003);
                return;
            }

            if (ds_buying.getRowCount() == 0) {
                row = ds_buying.insertRow();
            }else{
                row = ds_buying.insertRow(ds_buying.getRowPosition() + 1);
            }

            ds_buying.setCellData(row, "kcomcd", scwin.hd_kcomcd);
            ds_buying.setCellData(row, "blNo", cnd_ed_hhblno.getValue());
            ds_buying.setCellData(row, "mhno", cnd_lc_mhno.getValue());
            ds_buying.setCellData(row, "odrNo", ds_houseblList.getCellData(ds_houseblList.getRowPosition(), "odrNo"));
            ds_buying.setCellData(row, "drcrCls", "C");
            ds_buying.setCellData(row, "locPtnCls", "1");
            ds_buying.setCellData(row, "mblHblCls", "H");
            ds_buying.setCellData(row, "seaAirCls", "S");
            ds_buying.setCellData(row, "ppccCls", scwin.hd_hhpcgb);
            ds_buying.setCellData(row, "inpid", scwin.userId);

            ds_buying.setCellData(row, "pchsClntNo", ed_hhliner.getValue());
            ds_buying.setCellData(row, "pchsClntNm", txt_hhlinernm.getValue());
            ds_buying.setCellData(row, "rsltsStdDt", scwin.hd_creadyDt);
            ds_buying.setCellData(row, "exRateTyp", lc_bhhexgb.getValue()); // TODO: BindColVal
            ds_buying.setCellData(row, "pchsTyp", "1");
            ds_buying.setCellData(row, "chgWt", "1");     

            if (row > 0) {
                ds_buying.setCellData(row, "crcCd", ds_buying.getCellData(row - 1, "crcCd"));
            }

            await scwin.f_buyingUnitLoading();
            if (ds_buyingUnit.getRowCount() > 0) {
                ds_buying.setCellData(row, "fareUnit", ds_buyingUnit.getCellData(0, "code"));
            }
            scwin.f_packageRateBuyingLoading(row, "");

            gr_buying.focus();
            gr_buying.setFocusedCell(row, "pchsClntNo");

            if (ds_houseblList.getCellData(ds_houseblList.getRowPosition(), "hhbltype") == "L") {
                ds_buying.setCellData(row, "fareUnit", "R/T");
                scwin.f_packageRateBuyingLoading(row, "");
                gr_buying.focus();
                gr_buying.setFocusedCell(row, "pchsClntNo");
            }
            break;

        default:
        break;
    }
}

//---------------------------------------------------------
// 행삭제
//---------------------------------------------------------
scwin.f_FdeleteRow = function(disGubun) {
    switch (disGubun) {
        case 1: // Selling
            var rowPos1 = ds_selling.getRowPosition();
            for (var i = ds_selling.getRowCount() - 1; i >= 0; i--) {
                if (ds_selling.getCellData(i, "chk") == "T" || i == rowPos1) {
                    if ($c.util.isEmpty(ds_selling.getCellData(i, "certiNo"))) {
                        if (ds_selling.getRowStatus(i) === "C") {
                            ds_selling.removeRow(i);
                        } else {
                            ds_selling.deleteRow(i);
                        }
                    } else {
                        $c.gus.cfAlertMsg(E_MSG_CM_ERR_041, ["Invoice No", "delete"]);
                        return;
                    }
                }
            } // end for
            break;
        case 2: // Partner
            var rowPos2 = ds_partner.getRowPosition();
            for (var i = ds_partner.getRowCount() - 1; i >= 0; i--) {
                if (ds_partner.getCellData(i, "chk") == "T" || i == rowPos2) {
                    if ($c.util.isEmpty(ds_partner.getCellData(i, "certiNo"))) {
                        if (ds_partner.getRowStatus(i) === "C") {
                            ds_partner.removeRow(i);
                        } else {
                            ds_partner.deleteRow(i);
                        }
                    } else {
                        $c.gus.cfAlertMsg(E_MSG_CM_ERR_041, ["Invoice No", "delete"]);
                        return;
                    }
                }
            } // end for
            break;
        case 3: // Buying
            var rowPos3 = ds_buying.getRowPosition();
            for (var i = ds_buying.getRowCount() - 1; i >= 0; i--) {
                if (ds_buying.getCellData(i, "chk") == "T" || i == rowPos3) {
                    if ($c.util.isEmpty(ds_buying.getCellData(i, "pchsCertiNo"))) {
                        if (ds_buying.getCellData(i, "dcsnClsCd") == "확정") {
                            $c.gus.cfAlertMsg(E_MSG_CM_ERR_041, ["확정", "delete"]);
                            return;
                        } else {
                            if (ds_buying.getRowStatus(i) === "C") {
                                ds_buying.removeRow(i);
                            } else {
                                ds_buying.deleteRow(i);
                            }
                        }
                    } else {
                        $c.gus.cfAlertMsg(E_MSG_CM_ERR_041, ["Invoice No", "delete"]);
                        return;
                    }
                }
            } // end for 
            break;
    }
}

//---------------------------------------------------------
// 행취소
