scwin.f_FcancelRow = function(disGubun) {
	switch(disGubun){
		case 1: // Selling
            $c.data.undoAll(ds_selling);
			break;
		case 2: // Partner
            $c.data.undoAll(ds_partner);
			break;
		case 3: // Buying
            $c.data.undoAll(ds_buying);
			break;
	}
}

