		postDtDataSet_.setJSON(json);
	});
};

//---------------------------------------------------------------------------
//공통코드 조회
//---------------------------------------------------------------------------
scwin._comboQueue = Promise.resolve();

// 내부: responseJSON에서 path로 값 꺼내기
scwin._pick = function (obj, path, fallback) {
	if (!path) return (obj == undefined ? fallback : obj);
	var cur = obj;
	var parts = Array.isArray(path) ? path : String(path).split(".");
	for (var i = 0; i < parts.length; i++) {
		if (cur == null) return fallback;
		cur = cur[parts[i]];
	}
	return (cur == undefined ? fallback : cur);
};

// 내부: DataList에 JSON 반영
scwin._applyToDataList = function (dl, data) {
	if (!dl) return;
	if (dl.setJSON) {
		dl.setJSON(data);
		return;
	}
	throw new Error("Target DataList has no setJSON()");
};

scwin.execComboAndCopy = async function(params, options) {
    options = options || {};
    var target = options.target;
    var responsePath = options.responsePath || "GAUCE";
    var transform = options.transform;
    if (!target) throw new Error("options.target(DataList) is required");
    scwin._comboQueue = scwin._comboQueue.then(function () {
        dma_comCode.set("sysCd", params.sysCd || "");
        dma_comCode.set("queryId", params.queryId || "");
        dma_comCode.set("param1", params.param1 || "");
        dma_comCode.set("param2", params.param2 || "");
        dma_comCode.set("param3", params.param3 || "");
        dma_comCode.set("param4", params.param4 || "");
        dma_comCode.set("param5", params.param5 || "");
        dma_comCode.set("param6", params.param6 || "");
        dma_comCode.set("param7", params.param7 || "");
        dma_comCode.set("param8", params.param8 || "");
        dma_comCode.set("param9", params.param9 || "");
        dma_comCode.set("param10", params.param10 || "");
        dma_comCode.set("param11", params.param11 || "");
        dma_comCode.set("param12", params.param12 || "");
        dma_comCode.set("param13", params.param13 || "");
        dma_comCode.set("param14", params.param14 || "");
        return async function () {
            return await $c.sbm.execute($p, sbm_comCode).then(function (e) {
                var json = e && e.responseJSON ? e.responseJSON : {};
                var data = scwin._pick(json, responsePath, null);
                if (transform) data = transform(data, e);
                scwin._applyToDataList(target, data);
                return e;
            });
        }();
    });
    scwin._comboQueue = scwin._comboQueue.catch(function () {});
    return scwin._comboQueue;
};

scwin._parseQuery = function (url) {
    var idx = String(url || "").indexOf("?");
    if (idx < 0) return {};
    var q = url.substring(idx + 1);
    var obj = {};
    var parts = q.split("&");
    for (var i = 0; i < parts.length; i++) {
        if (!parts[i]) continue;
        var kv = parts[i].split("=");
        var key = decodeURIComponent(kv[0] || "");
        var val = decodeURIComponent((kv[1] || "").replace(/\+/g, " "));
        obj[key] = val;
    }
    return obj;
};

scwin._execDataId = function (ds, url) {
    var q = scwin._parseQuery(url);
    var params = {
        sysCd: q.sysCd || "",
        queryId: q.queryId || "",
        param1: q.param1 || "",
        param2: q.param2 || "",
        param3: q.param3 || "",
        param4: q.param4 || "",
        param5: q.param5 || "",
        param6: q.param6 || "",
        param7: q.param7 || "",
        param8: q.param8 || "",
        param9: q.param9 || "",
        param10: q.param10 || "",
        param11: q.param11 || "",
        param12: q.param12 || "",
        param13: q.param13 || "",
        param14: q.param14 || ""
    };

	$c.gus.cfCopyDataSet(ds_commCode,ds);

    if (ds && ds.removeAll) ds.removeAll();
    return scwin.execComboAndCopy(params, {
        target: ds
    });
};

//-------------------------------------------------------------------------
// Converted: scwin.f_OnLoad ~ before scwin.f_Retrieve
//-------------------------------------------------------------------------
scwin._insertRow = function(ds) {
    if (!ds || !ds.insertRow) return;
    ds.insertRow(ds.getRowCount());
};

scwin._clearDataMap = function(dm) {
    if (!dm) return;
    if (typeof dm.undo === "function") { dm.undo(); return; }
};


//-------------------------------------------------------------------------
// 공통 이벤트 유틸
//-------------------------------------------------------------------------
scwin._isModified = function(comp) {
    if (!comp) return false;
    if (typeof comp.isModified === "function") return comp.isModified();
    if (typeof comp.getModified === "function") return comp.getModified();
    if (typeof comp.Modified !== "undefined") return comp.Modified;
    return true;
};

scwin._valueRow = function(ds, colId, value) {
    var cnt = ds.getRowCount();
    for (var i = 0; i < cnt; i++) {
        if (String(ds.getCellData(i, colId)) === String(value)) return String(i + 1);
    }
    return "0";
};


//---------------------------------------------------------
// function name : scwin.f_validate
// function desc :
//---------------------------------------------------------
scwin.f_validate = async function() {
    var ret = await $c.gus.cfValidate([ed_hhetd, ed_hhondt, ed_hheta, ed_hhisudt, ed_creadyDt]);
    if (!ret) return false;

    if (ed_hheta.getValue() == "") {
        $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["ETA"]);
        tab_main.setSelectedTabIndex(0);
        ed_hheta.focus();
        return false;
    }

    var _curDt = $c.date.parseDate("yyyyMMdd", scwin.strCurDate);
    var _etdDt = $c.date.parseDate("yyyyMMdd", ed_hhetd.getValue());
    var _etaDt = $c.date.parseDate("yyyyMMdd", ed_hheta.getValue());

    if ($c.gus.cfMonthsBetween(_curDt, _etdDt) > 3) {
        alert("ETD가 저장하는 날짜로 부터 3개월 이상의 미래일 수 없습니다.");
        tab_main.setSelectedTabIndex(0);
        ed_hhetd.focus();
        return false;
    }

    if ($c.gus.cfMonthsBetween(_curDt, _etaDt) > 3) {
        alert("ETA가 저장하는 날짜로 부터 3개월 이상의 미래일 수 없습니다.");
        tab_main.setSelectedTabIndex(0);
        ed_hheta.focus();
        return false;
    }

    if ($c.gus.cfYearsBetween(_etdDt, _curDt) > 3) {
        alert("ETD가 3년 이상의 과거 일 수 없습니다.");
        tab_main.setSelectedTabIndex(0);
        ed_hhetd.focus();
        return false;
    }

    if ($c.gus.cfYearsBetween(_etaDt, _curDt) > 3) {
        alert("ETA가 3년 이상의 과거 일 수 없습니다.");
        tab_main.setSelectedTabIndex(0);
        ed_hheta.focus();
        return false;
    }

    if (WebSquare.date.dateDiff(ed_hhetd.getValue(), ed_hheta.getValue()) > 149) {
        alert("ETA-ETD(transit time)가 150일을 초과할 수 없습니다.");
        tab_main.setSelectedTabIndex(0);
        ed_hhetd.focus();
        return false;
    }

    //EDI ITEM 필수값 체크 - 20/02/18 현업요청으로 저장시, 필수값 체크 넣었으나 다시 빼달라는 요청으로 주석처리.
    if (txt_hhmitem2.getValue() == "") {
        $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["EDI ITEM"]);
        tab_main.setSelectedTabIndex(0);
        txt_hhmitem2.focus();
        return false;
    }

    if (ed_hhbuyer.getValue() == "") {
        $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Department"]);
        tab_main.setSelectedTabIndex(0);
        ed_hhbuyer.focus();
        return false;
    }

    if (!ilcommon.cf_ChkInputOnlyNumberAndAlphabet || !ilcommon.cf_ChkInputOnlyNumberAndAlphabet(txt_hhmitem2.getValue())) {
        alert("EDI ITEM에 특수문자만 입력은 불가능합니다.");
        return false;
    }

    if ($c.gus.cfGetByteLength(txt_hhmitem2.getValue()) < 2) {
        alert("EDI ITEM에 2글자 이상을 입력하셔야합니다.");
        return false;
    }

    if (lc_contractno.getValue() == "") { // TODO: BindColVal
        alert("계약은 필수항목 입니다. Customer를 확인하세요.");
        tab_main.setSelectedTabIndex(0);
        ed_hhactcust.focus();
        return false;
    }

    // TODO: ds_customerInfo 조회 submission 처리 필요
    // if (ds_customerInfo.getRowCount() > 0) { ... }

    // Buying Inner Dept
    for (var i = 0; i < ds_buying.getRowCount(); i++) {
        if (ds_buying.getCellData(i, "pchsTyp") == "3" && ds_buying.getCellData(i, "sellDeptCd") == "") {
            $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Inner Department"]);
            gr_buying.focus();
            var rowIdx = ds_buying.getRowPosition();
            gr_buying.setFocusedCell((rowIdx == null ? 0 : rowIdx), "sellDeptCd", true);
            return false;
        }
    }

    // Buying Unit
    for (var j = 0; j < ds_buying.getRowCount(); j++) {
        if (ds_buying.getCellData(j, "fareUnit") == "") {
            $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Unit"]);
            gr_buying.focus();
            var rowIdx = ds_buying.getRowPosition();
            gr_buying.setFocusedCell((rowIdx == null ? 0 : rowIdx), "fareUnit", true);
            return false;
        }
    }

    if (lc_hhbltype.getValue() == "" || lc_hhbltype.getValue() == null) { // TODO: BindColVal
        $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["B/L Type"]);
        return false;
    }

    return true;
}

//---------------------------------------------------------
// 공통팝업 공용 유틸
//---------------------------------------------------------
scwin._getCommonUdc = function() {
    if (typeof udc_ilcomCode !== "undefined") return udc_ilcomCode;
    if (typeof udc_comCode !== "undefined") return udc_comCode; // TODO: 공통팝업 UDC ID 확인
    return null;
};

scwin._normalizeRtn = function(rtnList) {
    if (typeof rtnList === "undefined" || rtnList === null) return null;
    if (rtnList.length !== undefined && rtnList.length === 0) return null;
    return rtnList;
};

scwin.openCommon = function(args) {
    var udc = scwin._getCommonUdc();
    if (!udc || !udc.ilCommonPopUp) {
        // TODO: 공통팝업 UDC 인스턴스 확인 필요
        return;
    }

    var onReturn = function(rtnList) {
        var r = scwin._normalizeRtn(rtnList);
        if (!r) {
            if (args.onEmpty) args.onEmpty();
            return;
        }
        if (args.onReturn) args.onReturn(rtnList, r);
    };

    udc.setSelectId(args.selectId);
    udc.ilCommonPopUp(
        onReturn,
        args.codeValue || "",
        args.nameValue || "",
        args.winCloseTF,
        args.colCnt,
        args.titles,
        args.widths,
        args.hideCols,
        args.whereOpt || "",
        args.winW || "500",
        args.winH || "500",
        args.posY || "",
        args.posX || "",
        args.dupTF || "",
        args.allTF || "F",
        args.winTitle,
        args.noDataTF || "F"
    );
};

