                null,                           // 윈도우 위치 X좌표
                null,                           // 중복체크여부	("F")
                "F",                            // 전체검색허용여부	("F")
                null);							// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")                     
            break;
        case "Vessel":
        case "Loading":
        case "Discharge":
        case "Unit":
        case "Salesman":
        case "DEPT":
        case "Receipt":
        case "Delivery":
        case "Destination":
        case "Item":
        case "Warehouse":
        case "ContainerType1":
        case "ContainerType2":
        case "ContainerType3":
