//-------------------------------------------------------------------------
// function name : scwin.f_PopUpGrid
// function desc : Grid popup
//-------------------------------------------------------------------------
scwin.f_PopUpGrid = function(disGubun, row, pWinCloseTF, pAllSearchTF, pNoDataCloseTF) {
    var rtnList;    
    var allTF = pAllSearchTF || "F";
    var noDataTF = pNoDataCloseTF || "F";

    switch (disGubun) {
        case "mctype":
            scwin.openCommon({
                selectId: "retriveContainerTypeCodeInfo",
                codeValue: ds_ocContList.getCellData(row, "mctype"),
                nameValue: "",
                winCloseTF: pWinCloseTF,
                colCnt: "2",
                titles: "Code, Name",
                widths: "80,230",
                hideCols: "3,4,5,6,7,8,9,10",
                allTF: allTF,
                winTitle: "Type,Code,Name",
                noDataTF: noDataTF,
                onReturn: function(rtnList) {
                    $c.gus.cfSetGridReturnValue(rtnList, ds_ocContList, row, "mctype", "mctypeNm");
                }
            });
            break;
        case "mcpkgcd":
            scwin.openCommon({
                selectId: "retrieveCommCdInfo",
                codeValue: ds_ocContList.getCellData(row, "mcpkgcd"),
                nameValue: "",
                winCloseTF: pWinCloseTF,
                colCnt: "2",
                titles: "Code, Name",
                widths: "80,230",
                hideCols: "3,4,5,6,7,8,9,10",
                whereOpt: "IL002",
                allTF: allTF,
                winTitle: "Unit,Code,Name",
                noDataTF: noDataTF,
                onReturn: function(rtnList) {
                    $c.gus.cfSetGridReturnValue(rtnList, ds_ocContList, row, "mcpkgcd", "mcpkgcdNm");
                }
            });
            break;
        case "SellingCustomer":
            scwin.openCommon({
                selectId: "retrieveEngClntInfo",
                codeValue: ds_selling.getCellData(row, "bilgClntNo"),
                nameValue: ds_selling.getCellData(row, "bilgClntNm"),
                winCloseTF: pWinCloseTF,
                colCnt: "10",
                titles: "Customer Code,Customer Name,Address1,Address2,Address3,Address4,Tel,,,CRN",
                widths: "140,300,100,100,100,100,100,,,100",
                hideCols: "8,9",
                allTF: allTF,
                winTitle: "Customer search,Customer Code,Customer Name",
                noDataTF: noDataTF,
                onReturn: function(rtnList) {
                    $c.gus.cfSetGridReturnValue(rtnList, ds_selling, row, "bilgClntNo", "bilgClntNm");
                }
            });
            break;
        case "SellingFcode":
            scwin.openCommon({
                selectId: "retriveFreightCodeInfo",
                codeValue: ds_selling.getCellData(row, "fareEngCd"),
                nameValue: ds_selling.getCellData(row, "fareEngNm"),
                winCloseTF: pWinCloseTF,
                colCnt: "2",
                titles: "Code, Name",
                widths: "80,230",
                hideCols: "3,4,5,6,7,8,9,10",
                whereOpt: "S,1",
                allTF: allTF,
                winTitle: "FCode,Code,Name",
                noDataTF: noDataTF,
                onReturn: function(rtnList) {
                    $c.gus.cfSetGridReturnValue(rtnList, ds_selling, row, "fareEngCd", "fareEngNm");
                    if (typeof rtnList === "undefined") return;
                    ds_selling.setCellData(row, "sellItemCd", rtnList[3]);
                    ds_selling.setCellData(row, "fareGrpCd", rtnList[5]);
                    ds_selling.setCellData(row, "vatYn", rtnList[7]);
                    if (rtnList[9] == "1") {
                        ds_selling.setCellData(row, "crcCd", "KRW");
                    }else{
                        ds_selling.setCellData(row, "crcCd", lc_shhcucd.getValue()); // TODO: BindColVal
                    }
                    if (ds_selling.getCellData(row, "fareEngCd") == "OCF") {
                        ds_selling.setCellData(row, "crcCd", "USD");
                    }
                    if (ds_selling.getCellData(row, "fareEngCd") == "DOC" || ds_selling.getCellData(row, "fareEngCd") == "DOCV"
                    || ds_selling.getCellData(row, "fareEngCd") == "DOF" || ds_selling.getCellData(row, "fareEngCd") == "DOFV"
                    || ds_selling.getCellData(row, "fareEngCd") == "INSU" || ds_selling.getCellData(row, "fareEngCd") == "HDC"
                    || ds_selling.getCellData(row, "fareEngCd") == "HDCV" || ds_selling.getCellData(row, "fareEngCd") == "CCFV"
                    || ds_selling.getCellData(row, "fareEngCd") == "CCF") {
                        ds_selling.setCellData(row, "fareUnit", "CASE");
                        ds_selling.setCellData(row, "chgWt", "1");
                    }
                }
            });
            break;
        case "PartnerCustomer":
            scwin.openCommon({
                selectId: "retrieveEngClntInfo",
                codeValue: ds_partner.getCellData(row, "bilgClntNo"),
                nameValue: ds_partner.getCellData(row, "bilgClntNm"),
                winCloseTF: pWinCloseTF,
                colCnt: "10",
                titles: "Customer Code,Customer Name,Address1,Address2,Address3,Address4,Tel,,,CRN",
                widths: "140,300,100,100,100,100,100,,,100",
                hideCols: "8,9",
                allTF: allTF,
                winTitle: "Customer search,Customer Code,Customer Name",
                noDataTF: noDataTF,
                onReturn: function(rtnList) {
                    $c.gus.cfSetGridReturnValue(rtnList, ds_partner, row, "bilgClntNo", "bilgClntNm");
                }
            });
            break;
        case "PartnerFcode":
            var whereOpt = "";
            if (ds_partner.getCellData(row, "drcrCls") == "D") {
                whereOpt = "S,0,1";
            }else if(ds_partner.getCellData(row, "drcrCls") == "C") {
                whereOpt = "S,0,2";
            }
            scwin.openCommon({
                selectId: "retriveFreightCodeInfo",
                codeValue: ds_partner.getCellData(row, "fareEngCd"),
                nameValue: ds_partner.getCellData(row, "fareEngNm"),
                winCloseTF: pWinCloseTF,
                colCnt: "2",
                titles: "Code, Name",
                widths: "80,230",
                hideCols: "3,4,5,6,7,8,9,10",
                whereOpt: whereOpt,
                allTF: allTF,
                winTitle: "FCode,Code,Name",
                noDataTF: noDataTF,
                onReturn: function(rtnList) {
                    $c.gus.cfSetGridReturnValue(rtnList, ds_partner, row, "fareEngCd", "fareEngNm");
                    if (typeof rtnList === "undefined") return;
                    ds_partner.setCellData(row, "sellItemCd", rtnList[3]);
                    ds_partner.setCellData(row, "fareGrpCd", rtnList[5]);
                    ds_partner.setCellData(row, "vatYn", rtnList[7]);
                    ds_partner.setCellData(row, "vehclYn", rtnList[8]);
                    ds_partner.setCellData(row, "crcCd", "USD");
                    if (ds_partner.getCellData(row, "fareEngCd") == "DOC" || ds_partner.getCellData(row, "fareEngCd") == "DOCV"
                    || ds_partner.getCellData(row, "fareEngCd") == "DOF" || ds_partner.getCellData(row, "fareEngCd") == "DOFV"
                    || ds_partner.getCellData(row, "fareEngCd") == "INSU" || ds_partner.getCellData(row, "fareEngCd") == "HDC"
                    || ds_partner.getCellData(row, "fareEngCd") == "HDCV" || ds_partner.getCellData(row, "fareEngCd") == "CCFV"
                    || ds_partner.getCellData(row, "fareEngCd") == "CCF") {
                        ds_partner.setCellData(row, "fareUnit", "CASE");
                        ds_partner.setCellData(row, "chgWt", "1");
                    }
                }
            });
            break;
        case "BuyingCustomer":
            scwin.openCommon({
                selectId: "retrieveEngClntInfo",
                codeValue: ds_buying.getCellData(row, "pchsClntNo"),
                nameValue: ds_buying.getCellData(row, "pchsClntNm"),
                winCloseTF: pWinCloseTF,
                colCnt: "10",
                titles: "Customer Code,Customer Name,Address1,Address2,Address3,Address4,Tel,,,CRN",
                widths: "140,300,100,100,100,100,100,,,100",
                hideCols: "8,9",
                allTF: allTF,
                winTitle: "Customer search,Customer Code,Customer Name",
                noDataTF: noDataTF,
                onReturn: function(rtnList) {
                    $c.gus.cfSetGridReturnValue(rtnList, ds_buying, row, "pchsClntNo", "pchsClntNm");
                }
            });
            break;
        case "BuyingFcode":
            scwin.openCommon({
                selectId: "retriveFreightCodeInfo",
                codeValue: ds_buying.getCellData(row, "fareEngCd"),
                nameValue: ds_buying.getCellData(row, "fareEngNm"),
                winCloseTF: pWinCloseTF,
                colCnt: "2",
                titles: "Code, Name",
                widths: "80,230",
                hideCols: "3,4,5,6,7,8,9,10",
                whereOpt: "S,2",
                allTF: allTF,
                winTitle: "FCode,Code,Name",
                noDataTF: noDataTF,
                onReturn: function(rtnList) {
                    $c.gus.cfSetGridReturnValue(rtnList, ds_buying, row, "fareEngCd", "fareEngNm");
                    if (typeof rtnList === "undefined") return;
                    ds_buying.setCellData(row, "selpchItemCd", rtnList[3]);
                    ds_buying.setCellData(row, "fareGrpCd", rtnList[5]);
                    ds_buying.setCellData(row, "vatYn", rtnList[7]);
                    ds_buying.setCellData(row, "vehclYn", rtnList[8]);
                    if (scwin.v_linkcheck != 9) {
                        if (rtnList[9] == "1") {
                            ds_buying.setCellData(row, "crcCd", "KRW");
                        }else{
                            ds_buying.setCellData(row, "crcCd", lc_bhhcucd.getValue()); // TODO: BindColVal
                        }
                        if (ds_buying.getCellData(row, "fareEngCd") == "OCF") {
                            ds_buying.setCellData(row, "crcCd", "USD");
                        }
                    }
                    if (ds_buying.getCellData(row, "fareEngCd") == "DOC" || ds_buying.getCellData(row, "fareEngCd") == "DOCV"
                    || ds_buying.getCellData(row, "fareEngCd") == "DOF" || ds_buying.getCellData(row, "fareEngCd") == "DOFV"
                    || ds_buying.getCellData(row, "fareEngCd") == "INSU" || ds_buying.getCellData(row, "fareEngCd") == "HDC"
                    || ds_buying.getCellData(row, "fareEngCd") == "HDCV" || ds_buying.getCellData(row, "fareEngCd") == "CCFV"
                    || ds_buying.getCellData(row, "fareEngCd") == "CCF") {
                        ds_buying.setCellData(row, "fareUnit", "CASE");
                        ds_buying.setCellData(row, "chgWt", "1");
                    }
                }
            });
            break;
        case "BuyingDept":
            scwin.openCommon({
                selectId: "retrieveOpDeptCdInfo",
                codeValue: ds_buying.getCellData(row, "sellDeptCd"),
                nameValue: ds_buying.getCellData(row, "sellDeptNm"),
                winCloseTF: pWinCloseTF,
                colCnt: "2",
                titles: "Code, Name",
                widths: "80,230",
                hideCols: "3,4,5,6,7,8,9,10",
                allTF: allTF,
                winTitle: "Department,Code,Name",
                noDataTF: noDataTF,
                onReturn: function(rtnList) {
                    $c.gus.cfSetGridReturnValue(rtnList, ds_buying, row, "sellDeptCd", "sellDeptNm");
                }
            });
            break;
        default:
            break;
    }
};

