scwin.f_autoCreateDoorOrderInfo = function () {
    ds_containerBookingList.removeAll();
    ds_containerDoorOrder.removeAll();
    ds_containerDoorOrderQty.removeAll();
    //한행추가
    ds_containerBookingList.insertRow(0);
    ds_containerDoorOrder.insertRow(0);
    ds_containerDoorOrderQty.insertRow(0);

    //ds_containerBookingCont에 기본값 설정
    ds_containerDoorOrder.setCellData(0, "kcomcd", scwin.hd_kcomcd);
    ds_containerDoorOrder.setCellData(0, "bkNo", ed_hhbkgno.getValue());
    ds_containerDoorOrder.setCellData(0, "doordt", scwin.strCurDate + scwin.currentTime);	//ORDER DATE
    ds_containerDoorOrder.setCellData(0, "bkdoorseq", "01");		//ORDER SEQ
    ds_containerDoorOrder.setCellData(0, "internalTyp", "2");	//1:내부부서,2:거래처
    ds_containerDoorOrder.setCellData(0, "transcd", "109856");	//운송사 CODE
    ds_containerDoorOrder.setCellData(0, "inpid", scwin.userId);

    //ds_containerDoorOrderQty에 기본값 설정
    ds_containerDoorOrderQty.setCellData(0, "kcomcd", scwin.hd_kcomcd);
    ds_containerDoorOrderQty.setCellData(0, "bkNo", ed_hhbkgno.getValue());
    ds_containerDoorOrderQty.setCellData(0, "bkdoorseq", "01");	//ORDER SEQ
    if (lc_hhbltype.getValue() == "F") {
        ds_containerDoorOrderQty.setCellData(0, "qtytype", "22GP");	//CONTAINER TYPE OR LCL
    }else if(lc_hhbltype.getValue() == "L") {
        ds_containerDoorOrderQty.setCellData(0, "qtytype", "R/T");	//CONTAINER TYPE OR LCL
    }
    ds_containerDoorOrderQty.setCellData(0, "inpid", scwin.userId);
}

