    }
    return false;
}

scwin.f_buyingAmt = function (Row,Colid,olddata){
    if (ds_buying.getCellData(Row, "crcCd") == "KRW") {
        ds_buying.setCellData(Row, "pchsAmt", Math.round(Number(ds_buying.getCellData(Row, "chgWt")) * Number(ds_buying.getCellData(Row, "pchsUpr"))));
    }else if (ds_buying.getCellData(Row, "crcCd") == "JPY" || ds_buying.getCellData(Row, "crcCd") == "ITL"
    || ds_buying.getCellData(Row, "crcCd") == "IDR" || ds_buying.getCellData(Row, "crcCd") == "ESP" ){
        ds_buying.setCellData(Row, "pchsAmt", Math.round(Number(ds_buying.getCellData(Row, "pchsAmtFcrc")) * Number(ds_buying.getCellData(Row, "exRate")))/100);
    }else {
        ds_buying.setCellData(Row, "pchsAmt", Math.round(Number(ds_buying.getCellData(Row, "pchsAmtFcrc")) * Number(ds_buying.getCellData(Row, "exRate"))));
    }
}

