scwin.f_BuyingSum = function (){
    let v_BuyingSumAmount = 0;
    let v_BuyingSumAmountW = 0;
    let v_BuyingSumVat = 0;
    let v_BuyingSumAmountUs = 0;
    let v_BuyingAmountSum = 0;
    for ( var i = 0; i< ds_buying.getRowCount(); i++) {
        if (ds_buying.getRowStatus(i) != "D") {
            v_BuyingSumAmount += Number(ds_buying.getCellData(i, "pchsAmtFcrc"));
            v_BuyingSumAmountW += Number(ds_buying.getCellData(i, "pchsAmt"));
            v_BuyingSumVat += Number(ds_buying.getCellData(i, "vat"));
            v_BuyingSumAmountUs += Number(ds_buying.getCellData(i, "usdAmt"));
        }
    }
    ed_BuyingSumAmount.setValue(v_BuyingSumAmount);
    ed_BuyingSumAmountW.setValue(v_BuyingSumAmountW);
    ed_BuyingSumVat.setValue(v_BuyingSumVat);
    ed_BuyingSumAmountUs.setValue(v_BuyingSumAmountUs);
    v_BuyingAmountSum = v_BuyingSumAmountW + v_BuyingSumVat;
    ed_BuyingAmountSum.setValue(v_BuyingAmountSum);
}

scwin.f_buyingTariffRateLoading = async function(){

    scwin._clearDataMap(dma_retrieveTariff);
    ds_resultTariff.removeAll();

    dma_retrieveTariff.set("fgubn", '2');  //selling , partner : 1, buying : 2
    dma_retrieveTariff.set("kcomcd", scwin.hd_kcomcd);  //KCOMCD
    dma_retrieveTariff.set("apdt", ed_hheta.getValue()); //ETA
    dma_retrieveTariff.set("customer", ed_hhactcust.getValue() ); //selling,buying : customer, partner:partner
    dma_retrieveTariff.set("partner", "" ); //partner시만 사용
    dma_retrieveTariff.set("liner", ed_hhliner.getValue() ); //LINER
    dma_retrieveTariff.set("loading", ed_hhlodcd.getValue() ); //LOADING
    dma_retrieveTariff.set("discharge", ed_hhdisccd.getValue() ); //DISCHARGE
    dma_retrieveTariff.set("item", scwin.hd_hhitem); //ITEM
    dma_retrieveTariff.set("cbgubn", "C" ); //CONTAINER OR BULK
    dma_retrieveTariff.set("incoterm", "" ); //INCOTERM(bulk시 사용)
    dma_retrieveTariff.set("userid", scwin.userId ); //user id
    dma_retrieveTariff.set("dangerous", scwin.hd_hhdanggb); //dangerous
    dma_retrieveTariff.set("commcustomer", scwin.hd_commcustomer ); //공통 customer
    dma_retrieveTariff.set("fcode", ds_buying.getCellData(ds_buying.getRowPosition(), "fareEngCd") ); //FCODE
    dma_retrieveTariff.set("currency", ds_buying.getCellData(ds_buying.getRowPosition(), "crcCd") ); //CURR
    dma_retrieveTariff.set("funit", ds_buying.getCellData(ds_buying.getRowPosition(), "fareUnit") ); //TYPE - FUNIT
    dma_retrieveTariff.set("flag", "2" ); //tariff : 1, tariffRate:2
    dma_retrieveTariff.set("transTariffYn", "Y" ); //TRANS TARIFF YN
    dma_retrieveTariff.set("blNo", cnd_ed_hhblno.getValue() ); //BLNO
    dma_retrieveTariff.set("mhno", cnd_lc_mhno.getValue() ); //MHNO

    await $c.sbm.execute(sbm_retrieveTariff); 

    if (ds_resultTariff.getRowCount() =="0") {
        $c.gus.cfAlertMsg(E_MSG_CM_WRN_002); // 조회결과가 존재하지 않습니다.
        return;
    }

    ds_buying.setCellData(ds_buying.getRowPosition(), "pchsUpr", ds_resultTariff.getCellData(0, "amount")); //rate

}

