scwin.f_CheckFileExt = function (ext, path){
    ext = ext.toUpperCase();
    path = path.toUpperCase();
    elen = ext.length;
    flen = path.length;
    return (ext == path.substring((flen-elen), flen));
}

scwin.f_chgGridColumnToHouseBlDs = function (gubun, ds) {        
    for (var i=0; i<ds.getRowCount(); i++) {
        ds.setCellData(i, "kcomcd", scwin.hd_kcomcd);
        ds.setCellData(i, "blNo", cnd_ed_hhblno.getValue()); //update일때.
        ds.setCellData(i, "mhno", cnd_lc_mhno.getValue()); //update일때.
        ds.setCellData(i, "odrNo", ds_houseblList.getCellData(ds_houseblList.getRowPosition(), "odrNo"));

        ds.setCellData(i, "mblHblCls", "H"); //house/master
        ds.setCellData(i, "seaAirCls", "S"); // sea/air
        ds.setCellData(i, "ppccCls", scwin.hd_hhpcgb);      //pp/cc
        ds.setCellData(i, "inpid", scwin.userId);

        if (gubun == "0") {
            ds.setCellData(i, "bilgClntNo", ed_hhactcust.getValue());   //CUSTOMER
            ds.setCellData(i, "bilgClntNm", txt_hhactcustnm.getValue());   //CUSTOMER name

            ds.setCellData(i, "fareUnit", ds_sellingUnit.getCellData(0, "code"));
            ds.setCellData(i, "drcrCls", "D"); // DR/CR
            ds.setCellData(i, "locPtnCls", "1"); //국내 : 1, 해외 :2
            ds.setCellData(i, "exRateTyp", lc_shhexgb.getValue());  //exgb
        }else if(gubun == "1") {
            ds.setCellData(i, "bilgClntNo", ed_hhagent.getValue());
            ds.setCellData(i, "bilgClntNm", txt_hhagentnm.getValue());   //partner name

            ds.setCellData(i, "fareUnit", ds_partnerUnit.getCellData(0, "code"));
            ds.setCellData(i, "drcrCls", "C"); // DR/CR
            ds.setCellData(i, "locPtnCls", "2"); //국내 : 1, 해외 :2
            ds.setCellData(i, "exRateTyp", lc_phhexgb.getValue());  //exgb
        }else if(gubun == "2") {            
            //ds.setCellData(i, "pchsClntNo", ed_hhliner.getValue());
            //ds.setCellData(i, "pchsClntNm", txt_hhlinernm.getValue());   //Liner name

            ds.setCellData(i, "fareUnit", ds_buyingUnit.getCellData(0, "code"));
            ds.setCellData(i, "pchsTyp", "1");
            ds.setCellData(i, "drcrCls", "C"); // DR/CR
            ds.setCellData(i, "locPtnCls", "1"); //국내 : 1, 해외 :2
            ds.setCellData(i, "exRateTyp", lc_bhhexgb.getValue());  //exgb
        }

        ds.setCellData(i, "rsltsStdDt", scwin.hd_creadyDt);  //실적일
        //		            ds.setCellData(i, "exRateTyp", lc_shhexgb.getValue());  //exgb

        ds.modifyRowStatus(i, "C");        
    }

    //unit처리.
    if (gubun == "0") {
        scwin.f_SellingSum();
    }else if(gubun == "1") {
        scwin.f_PartnerSum();
    }else if(gubun == "2") {
        scwin.f_BuyingSum();
    }
};

