    var v_containerCheck = "0";
    if (ed_hhcnt1type.getValue() != "" && ed_hhcnt2type.getValue() != "" && ed_hhcnt1type.getValue() == ed_hhcnt2type.getValue()) v_containerCheck = "1";
    if (ed_hhcnt1type.getValue() != "" && ed_hhcnt3type.getValue() != "" && ed_hhcnt1type.getValue() == ed_hhcnt3type.getValue()) v_containerCheck = "1";
    if (ed_hhcnt1type.getValue() != "" && ed_hhcnt4type.getValue() != "" && ed_hhcnt1type.getValue() == ed_hhcnt4type.getValue()) v_containerCheck = "1";
    if (ed_hhcnt2type.getValue() != "" && ed_hhcnt3type.getValue() != "" && ed_hhcnt2type.getValue() == ed_hhcnt3type.getValue()) v_containerCheck = "1";
    if (ed_hhcnt2type.getValue() != "" && ed_hhcnt4type.getValue() != "" && ed_hhcnt2type.getValue() == ed_hhcnt4type.getValue()) v_containerCheck = "1";
    if (ed_hhcnt3type.getValue() != "" && ed_hhcnt4type.getValue() != "" && ed_hhcnt3type.getValue() == ed_hhcnt4type.getValue()) v_containerCheck = "1";
    if (v_containerCheck == "1")  {
        $c.gus.cfAlertMsg(E_MSG_CM_ERR_032,Array("Container Type")); //  @은(는) 중복될 수 없습니다.
        return false;
    }else{
        return true;
    }
}

