scwin.f_ContractInfo = async function() {
    ds_ctrtNo.removeAll();
    ds_ctrtNo.insertRow(ds_ctrtNo.getRowCount());

    scwin._clearDataMap(dma_retrieveCtrtClnt);
    ;

    dma_retrieveCtrtClnt.set("ctrtNo", scwin.v_contractno);
