    dma_retrieveCtrtClnt.set("scDate", ed_hheta.getValue().trim());
    dma_retrieveCtrtClnt.set("ctrtDtYn", 1);	 //계약기간 여부
    dma_retrieveCtrtClnt.set("ctrtDistrictCd", "ZZA");	 // ZZA : 해운권역 , ZZB : 항공권역
    dma_retrieveCtrtClnt.set("impExpDomesticClsCd", "I"); // in/out
    if (lc_hhbltype.getValue() == "") {
        $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Cargo Type"]); //@는 필수입력항목입니다.
        return;
    }

    if (ed_hheta.getValue() == "") {

        dma_retrieveCtrtClnt.set("scDate", scwin.strCurDate);
    }

    if (lc_hhbltype.getValue() != "B") {
        dma_retrieveCtrtClnt.set("bizDivCntrYn", "1"); //container
    }else{
        dma_retrieveCtrtClnt.set("bizDivBulkYn", "1"); // bulk
    }

    var sbmResult = await $c.sbm.execute(sbm_retrieveCtrtClnt); if (scwin.sbm_tr_retrieveCtrtClnt_submitdone) { scwin.sbm_tr_retrieveCtrtClnt_submitdone(sbmResult); };
    //lc_contractno.setIndex(0);

    if(ds_ctrtNo.getRowCount() == 0){
        dma_retrieveCtrtClnt.set("ctrtClntNo", "999908");
        var sbmResult = await $c.sbm.execute(sbm_retrieveCtrtClnt); if (scwin.sbm_tr_retrieveCtrtClnt_submitdone) { scwin.sbm_tr_retrieveCtrtClnt_submitdone(sbmResult); };
        //lc_contractno.setIndex(0);
    }
}

