            scwin.f_ExRateHouseLoading(param1, param2, param3);

            dsPartner.setCellData(row, "exRate", ds_exHouseRate.getCellData(0, "code"));
        }
        break;
        case 3 :
        //		var dsBuying = ds_BuyingFreightInfo;
        if (colid == lc_cucd.getValue().trim()){
            dsBuying.setCellData(row, "exRate", ed_bhhuexrate.getValue());
        }else{
            param1 = dsBuying.getCellData(row, "crcCd");
            param2 = ed_exdt.getValue().trim();
            param3 = lc_exgb.getValue();

            scwin.f_ExRateHouseLoading(param1, param2, param3);

            dsBuying.setCellData(row, "exRate", ds_exHouseRate.getCellData(0, "code"));
        }
        break;
    }	// end switch
};

