scwin.f_HawbNoChange = async function (){
    var rtnList   = new Array();
    if (cnd_ed_hhblno.getValue().trim() != ""){

        let sURL = "/ui/il/common/xml/ilCommonHawbNoChange.xml";
        rtnList = await $c.win.openPopup(
            $p, 
            sURL, 
            {
                width: 460,
                height: 280,
                id: "pop_hawbNoChange",
                popupName: "House B/L no Change",          
                title: "House B/L no Change",      
            }, 
            {
                pBlno: cnd_ed_hhblno.getValue().trim()
            }
        ); 

        const flag = (rtnList[0] || "").trim();
        const newblNo = (rtnList[1] || "").trim();        

        if(typeof(rtnList) != "undefined"){

            if ( flag == "N/A" && !$c.util.isEmpty(newblNo) ) {
                //house no 변경  프소시저 호출 시작
                let ds = dma_HblNoChangeParam;

                ds.set("odrNo", ds_houseblList.getCellData(ds_houseblList.getRowPosition()), "odrNo");	// Order No
                ds.set("kcomcd", scwin.hd_kcomcd);	// 법인코드
                ds.set("blNo", cnd_ed_hhblno.getValue().trim());	// House Bill No
                ds.set("newblNo", newblNo);	// 변경할 House Bill No
                ds.set("mhno", ds_houseblList.getCellData(ds_houseblList.getRowPosition(), "mhno").trim());	// Consol No

                //$c.gus.cfAlertMsg(E_MSG_CM_ERR_049,["Selling Information"]); //  @이(가) 존재하지 않습니다.

                if(await $c.win.confirm(E_MSG_CM_CRM_001)){ //저장하시겠습니까?
                    await $c.sbm.execute(sbm_HblNoChange).then(function (rtn) {

                        let spMsg = ds_HblNoChangeResult.getRowCount() > 0 ? ds_HblNoChangeResult.getCellData(0, "spMsg") : "";
                        let spRtn = ds_HblNoChangeResult.getRowCount() > 0 ? ds_HblNoChangeResult.getCellData(0, "spRtn") : "-1";                        

                        if (spRtn == "0" ) { //변경 성공
                            cnd_ed_hhblno.setValue(newblNo);
                            cnd_lc_mhno.focus();
                            $c.gus.cfAlertMsg(scwin.MSG_LO_WRN_007);                            
                        }else if (spRtn == "-1" ){
                            alert("Invoice가 존재합니다.");
                        }else if (spRtn == "-2" ) { //새로운 번호가 존재 하는 경우 오류
                            $c.gus.cfAlertMsg(spMsg);
                        }else{
                            alert("실패하였습니다."); //일단 임의로 바꿈
                        }
                    });
                }
                //house no 변경  프로시저 호출 끝
            }
        }
    }
};

scwin.f_Import = function (){

    $c.gus.cfProgressWinClose();
    ds_tmp.setJSON(ds_ExcelInformation.getAllJSON());
    for(var i=0 ; i<ds_tmp.getRowCount(); i++) {
        ds_ocContList.insertRow(ds_ocContList.getRowCount());
        ds_ocContList.setCellData(i, "mccntno", ds_tmp.getCellData(i, "mccntno" ));
        ds_ocContList.setCellData(i, "mctype", ds_tmp.getCellData(i, "mctype" ));
        ds_ocContList.setCellData(i, "mcseal1", ds_tmp.getCellData(i, "mcseal1" ));
        ds_ocContList.setCellData(i, "mcseal2", ds_tmp.getCellData(i, "mcseal2" ));
        ds_ocContList.setCellData(i, "mcpkg", ds_tmp.getCellData(i, "mcpkg" ));
        ds_ocContList.setCellData(i, "mcpkgcd", ds_tmp.getCellData(i, "mcpkgcd" ));
        ds_ocContList.setCellData(i, "mcwgt", ds_tmp.getCellData(i, "mcwgt" ));
        ds_ocContList.setCellData(i, "mcmsr", ds_tmp.getCellData(i, "mcmsr" ));
        ds_ocContList.setCellData(i, "mcpart", ds_tmp.getCellData(i, "mcpart" ));
        //공통사항
        ds_ocContList.setCellData(i, "kcomcd", scwin.hd_kcomcd);
        ds_ocContList.setCellData(i, "mchblno", cnd_ed_hhblno.getValue());
        ds_ocContList.setCellData(i, "mhno", cnd_lc_mhno.getValue());
        ds_ocContList.setCellData(i, "inpid", scwin.userId);
    }

    ds_tmp.removeAll();
    gr_ocContList.Redraw = "true";
    //$c.gus.cfShowTotalRows(totalRows, ds_ocContList.getRowCount());
}

