                    vslcd: ed_hhvslcd.getValue(),
                    vsl: txt_hhvsl.getValue(),
                    vyg: txt_hhvyg.getValue()
                });
            }else{
                scwin._openMenu("Import Master B/L", "/ui/il/seainb/sibl/se_202_01_03b.xml", "se_202_01_03b.xml", {
