scwin.f_packageRateBuyingLoading = function (row,colid){
    var v_wgt = Number(ed_hhgwgt.getValue())/1000;
    var v_msr = Number(ed_hhmsr.getValue());
    var v_wgtR = Math.ceil(v_wgt) ;
    var v_msrR = Math.ceil(v_msr) ;
    var wgt = 0 ;
    var msr = 0 ;
    if (ds_buying.getCellData(ds_buying.getRowPosition(), "fareEngCd") == "WFG") {
        wgt = v_wgtR;
        msr = v_msrR;
    }else{
        wgt = v_wgt;
        msr = v_msr;
    }

    if (ds_buying.getCellData(ds_buying.getRowPosition(), "fareUnit") == "WGT" ) {
        //ds_buying.setCellData(ds_buying.getRowPosition(), "chgWt", ed_hhgwgt.getValue());
        if (ds_buying.getCellData(ds_buying.getRowPosition(), "fareEngCd") == "WFG") {
            ds_buying.setCellData(ds_buying.getRowPosition(), "chgWt", Math.ceil(Number(ed_hhgwgt.getValue())));
        }else{
            ds_buying.setCellData(ds_buying.getRowPosition(), "chgWt", ed_hhgwgt.getValue());
        }
    }else if(ds_buying.getCellData(ds_buying.getRowPosition(), "fareUnit") == "R/T" ) {
        if (v_wgt > v_msr) {
            ds_buying.setCellData(ds_buying.getRowPosition(), "chgWt", wgt);
        }else{
            ds_buying.setCellData(ds_buying.getRowPosition(), "chgWt", msr);
        }
    }else if(ds_buying.getCellData(ds_buying.getRowPosition(), "fareUnit") == "CBM") {
        ds_buying.setCellData(ds_buying.getRowPosition(), "chgWt", msr);
    }else if(ds_buying.getCellData(ds_buying.getRowPosition(), "fareUnit") == "M/T") {
        ds_buying.setCellData(ds_buying.getRowPosition(), "chgWt", ed_hhgwgt.getValue()/1000);
    }else if(ds_buying.getCellData(ds_buying.getRowPosition(), "fareUnit") == "CASE") {
        ds_buying.setCellData(ds_buying.getRowPosition(), "chgWt", "1");
    }else{
        if (ds_buying.getCellData(ds_buying.getRowPosition(), "fareUnit") == ed_hhcnt1type.getValue()) {
            ds_buying.setCellData(ds_buying.getRowPosition(), "chgWt", ed_hhcnt1.getValue());
        }else if(ds_buying.getCellData(ds_buying.getRowPosition(), "fareUnit") == ed_hhcnt2type.getValue()) {
            ds_buying.setCellData(ds_buying.getRowPosition(), "chgWt", ed_hhcnt2.getValue());
        }else if(ds_buying.getCellData(ds_buying.getRowPosition(), "fareUnit") == ed_hhcnt3type.getValue()) {
            ds_buying.setCellData(ds_buying.getRowPosition(), "chgWt", ed_hhcnt3.getValue());
        }else if(ds_buying.getCellData(ds_buying.getRowPosition(), "fareUnit") == ed_hhcnt4type.getValue()) {
            ds_buying.setCellData(ds_buying.getRowPosition(), "chgWt", ed_hhcnt4.getValue());
        }
    }

}

