scwin.f_partnerAmt = function (Row,Colid,olddata){
    if (ds_partner.getCellData(Row, "crcCd") == "KRW") {
        ds_partner.setCellData(Row, "sellAmt", Math.round(Number(ds_partner.getCellData(Row, "chgWt")) * Number(ds_partner.getCellData(Row, "sellUpr"))));
    }else if (ds_partner.getCellData(Row, "crcCd") == "JPY" || ds_partner.getCellData(Row, "crcCd") == "ITL"
    || ds_partner.getCellData(Row, "crcCd") == "IDR" || ds_partner.getCellData(Row, "crcCd") == "ESP" ){
        ds_partner.setCellData(Row, "sellAmt", Math.round(Number(Number(ds_partner.getCellData(Row, "sellAmtFcrc"))) * Number(ds_partner.getCellData(Row, "exRate")))/100);
    }else{
        ds_partner.setCellData(Row, "sellAmt", Math.round(Number(Number(ds_partner.getCellData(Row, "sellAmtFcrc"))) * Number(ds_partner.getCellData(Row, "exRate"))));
    }
}

scwin.f_partnerAmtFcrc = function (Row,Colid,olddata){

    if (ds_partner.getCellData(Row, "crcCd") == "KRW") {
        ds_partner.setCellData(Row, "sellAmtFcrc", "0");
    }else{
        ds_partner.setCellData(Row, "sellAmtFcrc", Math.round((Number(ds_partner.getCellData(Row, "chgWt")) * Number(ds_partner.getCellData(Row, "sellUpr"))) * 100) / 100);
    }
}

scwin.f_PartnerSum = function (){
    let v_PartnerSumAmount = 0;
    let v_PartnerSumAmountW = 0;
    let v_PartnerSumAmountUs = 0;
    for ( let i = 0; i< ds_partner.getRowCount(); i++) {
        if (ds_partner.getRowStatus(i) != "D") {
            v_PartnerSumAmount += Number(ds_partner.getCellData(i, "sellAmtFcrc"));
            v_PartnerSumAmountW += Number(ds_partner.getCellData(i, "sellAmt"));
            v_PartnerSumAmountUs += Number(ds_partner.getCellData(i, "usdAmt"));
        }
    }
    ed_PartnerSumAmount.setValue(v_PartnerSumAmount);
    ed_PartnerSumAmountW.setValue(v_PartnerSumAmountW);
    ed_PartnerSumAmountUs.setValue(v_PartnerSumAmountUs);
}

scwin.f_partnerTariffRateLoading = async function(){

    scwin._clearDataMap(dma_retrieveTariff);
    ds_resultTariff.removeAll();
    ;

    dma_retrieveTariff.set("fgubn", '3');  //selling , partner : 1, buying : 2
    dma_retrieveTariff.set("kcomcd", scwin.hd_kcomcd);  //KCOMCD
    dma_retrieveTariff.set("apdt", ed_hheta.getValue()); //ETA
    dma_retrieveTariff.set("customer", "" ); //selling,buying : customer, partner:partner
    dma_retrieveTariff.set("partner", ed_hhagent.getValue() ); //partner시만 사용
    dma_retrieveTariff.set("liner", "" ); //LINER
    dma_retrieveTariff.set("loading", ed_hhlodcd.getValue() ); //LOADING
    dma_retrieveTariff.set("discharge", ed_hhdisccd.getValue() ); //DISCHARGE
    dma_retrieveTariff.set("item", scwin.hd_hhitem); //ITEM
    dma_retrieveTariff.set("cbgubn", "C" ); //CONTAINER OR BULK
    dma_retrieveTariff.set("incoterm", "" ); //INCOTERM(bulk시 사용)
    dma_retrieveTariff.set("userid", scwin.userId ); //user id
    dma_retrieveTariff.set("dangerous", scwin.hd_hhdanggb); //dangerous
    dma_retrieveTariff.set("commcustomer", scwin.hd_commcustomer ); //공통 customer
    dma_retrieveTariff.set("fcode", ds_partner.getCellData(ds_partner.getRowPosition(), "fareEngCd") ); //FCODE
    dma_retrieveTariff.set("currency", ds_partner.getCellData(ds_partner.getRowPosition(), "crcCd") ); //CURR
    dma_retrieveTariff.set("funit", ds_partner.getCellData(ds_partner.getRowPosition(), "fareUnit") ); //TYPE - FUNIT
    dma_retrieveTariff.set("flag", "2" ); //tariff : 1, tariffRate:2
    dma_retrieveTariff.set("transTariffYn", "N" ); //TRANS TARIFF YN
    dma_retrieveTariff.set("blNo", "" ); //BLNO
    dma_retrieveTariff.set("mhno", "" ); //MHNO

    await $c.sbm.execute(sbm_retrieveTariff); 

    if (ds_resultTariff.getRowCount() =="0") {
        $c.gus.cfAlertMsg(E_MSG_CM_WRN_002); // 조회결과가 존재하지 않습니다.
        return;
    }

    ds_partner.setCellData(ds_partner.getRowPosition(), "sellUpr", ds_resultTariff.getCellData(0, "amount")); //rate

}

scwin.f_partnerUnitLoading = async function (){

    var cnt1 = "0";
    var cnt2 = "0";
    var cnt3 = "0";
    var cnt4 = "0";

    if(ed_hhcnt1type.getValue() != "" && ed_hhcnt1.getValue() != "0" ) {
        cnt1 = ed_hhcnt1type.getValue();
    }else{
        cnt1 = "0";
    }

    if(ed_hhcnt2type.getValue() != "" && ed_hhcnt2.getValue() != "0" ) {
        cnt2 = ed_hhcnt2type.getValue();
    }else{
        cnt2 = "0";
    }

    if(ed_hhcnt3type.getValue() != "" && ed_hhcnt3.getValue() != "0" ) {
        cnt3 = ed_hhcnt3type.getValue();
    }else{
        cnt3 = "0";
    }

    if(ed_hhcnt4type.getValue() != "" && ed_hhcnt4.getValue() != "0" ) {
        cnt4 = ed_hhcnt4type.getValue();
    }else{
        cnt4 = "0";
    }
    var url = "/cm.zz.RetrieveComboCMD.do?sysCd=SeaImportHouseEBC&queryId=retriveUnitList&param1=" + cnt1 + "&param2=" + cnt2 + "&param3=" + cnt3 + "&param4=" + cnt4;
    await scwin._execDataId(ds_partnerUnit, url);

}

scwin.f_partnerUsdAmt = function (Row,Colid,olddata){
