}

scwin.f_partnerVat = async function(Row,Colid,olddata)	{
    if (ds_partner.getCellData(Row, "vatYn") == "0") {
        ds_partner.setCellData(Row, "vatAmt", "0");
    }else{
        ds_partner.setCellData(Row, "vatAmt", Math.round((Number(ds_partner.getCellData(Row, "sellAmt")) * 0.1) * 100) / 100);
    }
}

