scwin.f_RunExcel = async function(varGrNm) {

    var grid = document.getElementById(varGrNm);

    if($c.gus.cfIsNull(grid)) return;

    var dataSet = document.getElementById(grid.DataId);

    if($c.gus.cfIsNull(dataSet)) return;

    totCnt      = dataSet.getRowCount();
    sheetTitle  = "Container List_"+cnd_ed_hhblno.getValue();
    cfrm = confirm("EXCEL로 다운로드 받으시겠습니까?");

    if(cfrm){
        $c.gus.cfGridToExcel(grid, sheetTitle, sheetTitle+".xls", 4+8+16);
    }
}

