scwin.f_Save = async function() {    
    let updated =
		ds_houseblList.getModifiedIndex().length > 0  ||
		ds_ocContList.getModifiedIndex().length > 0  ||
		ds_selling.getModifiedIndex().length > 0 ||
        ds_partner.getModifiedIndex().length > 0 ||
		ds_buying.getModifiedIndex().length > 0 ;

	if(!updated){
		await $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["House B/L"]);
        // await $c.sbm.execute(sbm_save);
		return;
	}

    if (!(await scwin.f_validate())) return;
    if (!(await scwin.f_validate_freight())) return;
    if (!(await scwin.f_JobCloseYn())) return;    

    //scwin._syncHiddenBeforeSave();
    scwin.f_TextareaSave();

    //동부 하이텍 인터페이스의 경우 수정에는 에러메세지만 뿌림
    if (scwin.statusFlag == "U" && (ds_hitekContents.getRowCount() > 0 )){
        $c.gus.cfAlertMsg(cnd_ed_hhblno.getValue()+" : "+'동부하이텍 인터페이스');
    }

    if(!(await $c.win.confirm(E_MSG_CM_CRM_001))){
		return;
	}

    // GPT에서 가져온 B/L인데, 기존에 동일한 B/L이 존재할 경우
    if (scwin.popUpResult != null && scwin.popUpResult[2] == 'Y' && cnd_ed_hhblno.getValue().trim() == scwin.popUpResult[0] && gptYn) {
        // 덮어 씌울껀지 확인.
        if (!$c.win.confirm("기존에 동일한 이름의 B/L이 존재합니다. 새로운 내용으로 덮어 씌우시겠습니까?")) {
            return;
        }
    }

    if (scwin.statusFlag == "C"){
        // DBEX
        if (cnd_ed_hhblno.getValue().trim() == "") {
            $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["House No"]);  // @은(는) 필수 입력 항목입니다.
            return;
        }

        ds_houseblList.setCellData(0, "hhbkgno", "");//House bl copy시 Booking No 초기화
        dma_retrieveBooking.set("kcomcd", scwin.hd_kcomcd);
        dma_retrieveBooking.set("bkEta", ed_hheta.getValue());   // 다른 dataset정보를  	dma_retrieve dataset에 넣음.
        dma_retrieveBooking.set("cfs", lc_hhbltype.getValue());   // 다른 dataset정보를  	dma_retrieve dataset에 넣음.

        var sbmResult = await $c.sbm.execute(sbm_retrievebookingNo); 
        ed_hhbkgno.setValue(ds_retrieveNo.getCellData(0, "bkNo"));
        scwin.f_autoCreateDoorOrderInfo();

        if (ds_bkseq.getRowCount() == 0){            
            ds_bkseq.insertJSON(0, [{code: "01", name: "01"}]);
        }

        // 저장
        ds_houseblList.setCellData(0, "kcomcd", scwin.hd_kcomcd);
        ds_houseblList.setCellData(0, "hhblno", cnd_ed_hhblno.getValue());
        ds_houseblList.setCellData(0, "hhbkgseq", lc_hhbkgseq.getValue());
        ds_houseblList.setCellData(0, "mhno", cnd_lc_mhno.getValue());
        ds_houseblList.setCellData(0, "hhio", scwin.hd_hhio);
        ds_houseblList.setCellData(0, "inpid", scwin.userId);
        ds_houseblList.setCellData(0, "hhmitem1", "일반화물"); //기존 입력 항목 없애면서 디폴트 일반화물로 입력
        ds_houseblList.setCellData(0, "hhbkgno", ed_hhbkgno.getValue());
        ds_houseblList.setCellData(0, "hhbkgseq", "01"); //저장성공

        for ( var i = 0; i< ds_ocContList.getRowCount(); i++) {
            ds_ocContList.setCellData(i, "kcomcd", scwin.hd_kcomcd);
            ds_ocContList.setCellData(i, "mchblno", cnd_ed_hhblno.getValue()); //update일때.
            ds_ocContList.setCellData(i, "mhno", cnd_lc_mhno.getValue()); //update일때.
            ds_ocContList.setCellData(i, "inpid", scwin.userId);
            ds_ocContList.modifyRowStatus(i, "C");  // insert 로 변경.
        }


        // 등록일 때 동부하이텍 인터페이스 필수입력항목 체크 함.
        var customer = ds_houseblList.getCellData(0, "hhactcust");
        if (customer == "125305" || customer == "125283") {
            if(!scwin.f_HiDataCheck()) return;
        }

        //OC_BK 테이블에 BOOKING 생성하기 위한 데이터셋 기본값 설정 // BOOKING은 CREATE시에만 처음 생성됨
        ds_containerBookingList.setRowPosition(0);
        ds_containerBookingList.setCellData(ds_containerBookingList.getRowPosition(), "kcomcd", scwin.hd_kcomcd);
        ds_containerBookingList.setCellData(ds_containerBookingList.getRowPosition(), "bkNo", ds_retrieveNo.getCellData(0, "bkNo"));
        ds_containerBookingList.setCellData(ds_containerBookingList.getRowPosition(), "wgt", 0);
        ds_containerBookingList.setCellData(ds_containerBookingList.getRowPosition(), "msr", 0);
        ds_containerBookingList.setCellData(ds_containerBookingList.getRowPosition(), "cfs", lc_hhbltype.getValue());
        ds_containerBookingList.setCellData(ds_containerBookingList.getRowPosition(), "dept", ed_hhbuyer.getValue());
        ds_containerBookingList.setCellData(ds_containerBookingList.getRowPosition(), "deptnm", txt_hhbuyernm.Value);
        ds_containerBookingList.setCellData(ds_containerBookingList.getRowPosition(), "contractno", lc_contractno.getValue());
        if (dma_retrieveCtrtClnt.get("ctrtClntNo") == "999908"){
            ds_containerBookingList.setCellData(ds_containerBookingList.getRowPosition(), "custCd", "999908");
            ds_containerBookingList.setCellData(ds_containerBookingList.getRowPosition(), "custNm", "공통거래처(국제)");
        }
        else {
            ds_containerBookingList.setCellData(ds_containerBookingList.getRowPosition(), "custCd", ed_hhactcust.getValue());
            ds_containerBookingList.setCellData(ds_containerBookingList.getRowPosition(), "custNm", txt_hhactcustnm.Value);
        }

        if (lc_hhbltype.getValue() == "B") {		 // Bulk
            ds_containerBookingList.setCellData(ds_containerBookingList.getRowPosition(), "bkbltype", "B");
        }else{
            ds_containerBookingList.setCellData(ds_containerBookingList.getRowPosition(), "bkbltype", "C");
        }
        ds_containerBookingList.setCellData(ds_containerBookingList.getRowPosition(), "bkEta", ed_hheta.getValue());
        ds_containerBookingList.setCellData(ds_containerBookingList.getRowPosition(), "bkEtd", ed_hhetd.getValue());
        ds_containerBookingList.setCellData(ds_containerBookingList.getRowPosition(), "inpid", scwin.userId);

        //freight에 bl번호 입력, 오더번호 초기화
        for ( var i = 0; i< ds_selling.getRowCount(); i++) {
            ds_selling.setCellData(i, "blNo", cnd_ed_hhblno.getValue());
            ds_selling.setCellData(i, "odrNo", "");
        }
        for ( var i = 0; i< ds_partner.getRowCount(); i++) {
            ds_partner.setCellData(i, "blNo", cnd_ed_hhblno.getValue());
            ds_partner.setCellData(i, "odrNo", "");
        }
        for ( var i = 0; i< ds_buying.getRowCount(); i++) {
            ds_buying.setCellData(i, "blNo", cnd_ed_hhblno.getValue());
            ds_buying.setCellData(i, "odrNo", "");
        }

        //BL Type이 direct일 경우, master bl 자동 생성
        if(cnd_lc_autono.getValue()=="DIRECT"){
            // MHNO NO 를 생성및 가져온다.
            //						dma_retrieve.set("mheta", ed_hheta.getValue());
            dma_retrieveMbl.set("mheta", ed_hheta.getValue());
            dma_retrieveMbl.set("hhblno", "");
            var sbmResult = await $c.sbm.execute(sbm_createMhno); if (scwin.sbm_tr_createMhno_submitdone) { scwin.sbm_tr_createMhno_submitdone(sbmResult); };

            ds_ocMblhList.removeAll();
            ds_ocMblhList.insertRow(ds_ocMblhList.getRowCount());

            //mhno 넣어 주기.
            ds_hmhno.removeAll();
            ds_hmhno.insertRow(ds_hmhno.getRowCount());
            ds_hmhno.setCellData(ds_hmhno.getRowPosition(), "code", ds_retrieveMhNo.getCellData(ds_retrieveNo.getRowPosition(), "mhno"));
            ds_hmhno.setCellData(ds_hmhno.getRowPosition(), "name", ds_retrieveMhNo.getCellData(ds_retrieveNo.getRowPosition(), "mhno"));
            //cnd_lc_mhno.setIndex(0);

            //Master BL생성시 필수값 넣어주기
            ds_ocMblhList.setCellData(ds_ocMblhList.getRowPosition(), "mhno", ds_retrieveMhNo.getCellData(ds_retrieveMhNo.getRowPosition(), "mhno"));
            ds_ocMblhList.setCellData(ds_ocMblhList.getRowPosition(), "mhio", scwin.hd_hhio);
            ds_ocMblhList.setCellData(ds_ocMblhList.getRowPosition(), "mhmblno", ds_houseblList.getCellData(0, "hhblno"));

            ds_ocMblhList.setCellData(ds_ocMblhList.getRowPosition(), "kcomcd", scwin.hd_kcomcd);
            ds_ocMblhList.setCellData(ds_ocMblhList.getRowPosition(), "mhbuyer", ed_hhbuyer.getValue());
            ds_ocMblhList.setCellData(ds_ocMblhList.getRowPosition(), "mhbuyernm", txt_hhbuyernm.getValue());
            ds_ocMblhList.setCellData(ds_ocMblhList.getRowPosition(), "mheta", ed_hheta.getValue());
            ds_ocMblhList.setCellData(ds_ocMblhList.getRowPosition(), "mhetd", ed_hhetd.getValue());
            ds_ocMblhList.setCellData(ds_ocMblhList.getRowPosition(), "mhcrdt", ed_creadyDt.getValue() ); //Result Date

            ds_ocMblhList.setCellData(ds_ocMblhList.getRowPosition(), "mhpkg", ed_hhpkg.getValue()  ); // PACKAGE(N10)
            ds_ocMblhList.setCellData(ds_ocMblhList.getRowPosition(), "mhwgt", ed_hhgwgt.getValue() );//weight(N12.3)
            ds_ocMblhList.setCellData(ds_ocMblhList.getRowPosition(), "mhmsr", ed_hhmsr.getValue() );//measure(N11.3)
            ds_ocMblhList.setCellData(ds_ocMblhList.getRowPosition(), "mhexrate", ed_shhexrate.getValue() );//환율(N11.3)

            //Master BL생성시 옵션사항 넣어주기
            ds_ocMblhList.setCellData(ds_ocMblhList.getRowPosition(), "mhvslcd", ed_hhvslcd.getValue() );
            ds_ocMblhList.setCellData(ds_ocMblhList.getRowPosition(), "mhvsl", txt_hhvsl.getValue() );
            ds_ocMblhList.setCellData(ds_ocMblhList.getRowPosition(), "mhvyg", txt_hhvyg.getValue() );
            ds_ocMblhList.setCellData(ds_ocMblhList.getRowPosition(), "mhlodcd", ed_hhlodcd.getValue()  );  //Loading
            ds_ocMblhList.setCellData(ds_ocMblhList.getRowPosition(), "mhlodnm", txt_hhdiscnm.getValue()  );  //Loading
            ds_ocMblhList.setCellData(ds_ocMblhList.getRowPosition(), "mhdisccd", ed_hhdisccd.getValue() ); //Discharge
            ds_ocMblhList.setCellData(ds_ocMblhList.getRowPosition(), "mhdiscnm", txt_hhlodnm.getValue() ); //Discharge
            ds_ocMblhList.setCellData(ds_ocMblhList.getRowPosition(), "mhunit", txt_hhunit.getValue() ); //Unit
            ds_ocMblhList.setCellData(ds_ocMblhList.getRowPosition(), "inpid", scwin.userId);

            ds_houseblList.setCellData(0, "mhno", ds_retrieveMhNo.getCellData(ds_retrieveMhNo.getRowPosition(), "mhno"));
            ds_houseblList.setCellData(0, "hhmblno", ds_houseblList.getCellData(0, "hhblno"));
            ds_houseblList.setCellData(ds_houseblList.getRowPosition(), "chk", "T");
        }

        for ( var i = 0; i< ds_ocContList.getRowCount(); i++) {
            ds_ocContList.setCellData(i, "kcomcd", scwin.hd_kcomcd);
            ds_ocContList.setCellData(i, "mchblno", cnd_ed_hhblno.getValue()); //update일때.
            ds_ocContList.setCellData(i, "mhno", cnd_lc_mhno.getValue()); //update일때.
            ds_ocContList.setCellData(i, "inpid", scwin.userId);
            ds_ocContList.modifyRowStatus(i, "C");  // insert 로 변경.
        }
    } // CREATE 끝

    else {
        //BL Type이 direct일 경우, master bl 자동 생성
        if(cnd_lc_autono.getValue()=="DIRECT"){
            //Master BL생성시 필수값 넣어주기
            ds_ocMblhList.setCellData(ds_ocMblhList.getRowPosition(), "mhno", cnd_lc_mhno.getValue());
            ds_ocMblhList.setCellData(ds_ocMblhList.getRowPosition(), "mhio", scwin.hd_hhio);
            ds_ocMblhList.setCellData(ds_ocMblhList.getRowPosition(), "mhmblno", ds_houseblList.getCellData(0, "hhblno"));

            ds_ocMblhList.setCellData(ds_ocMblhList.getRowPosition(), "kcomcd", scwin.hd_kcomcd);
            ds_ocMblhList.setCellData(ds_ocMblhList.getRowPosition(), "mhbuyer", ed_hhbuyer.getValue());
            ds_ocMblhList.setCellData(ds_ocMblhList.getRowPosition(), "mhbuyernm", txt_hhbuyernm.getValue());
            ds_ocMblhList.setCellData(ds_ocMblhList.getRowPosition(), "mheta", ed_hheta.getValue());
            ds_ocMblhList.setCellData(ds_ocMblhList.getRowPosition(), "mhetd", ed_hhetd.getValue());
            ds_ocMblhList.setCellData(ds_ocMblhList.getRowPosition(), "mhcrdt", ed_creadyDt.getValue() ); //Result Date

            ds_ocMblhList.setCellData(ds_ocMblhList.getRowPosition(), "mhpkg", ed_hhpkg.getValue()  ); // PACKAGE(N10)
            ds_ocMblhList.setCellData(ds_ocMblhList.getRowPosition(), "mhwgt", ed_hhgwgt.getValue() );//weight(N12.3)
            ds_ocMblhList.setCellData(ds_ocMblhList.getRowPosition(), "mhmsr", ed_hhmsr.getValue() );//measure(N11.3)
            ds_ocMblhList.setCellData(ds_ocMblhList.getRowPosition(), "mhexrate", ed_shhexrate.getValue() );//환율(N11.3)

            //Master BL생성시 옵션사항 넣어주기
            ds_ocMblhList.setCellData(ds_ocMblhList.getRowPosition(), "mhvslcd", ed_hhvslcd.getValue() );
            ds_ocMblhList.setCellData(ds_ocMblhList.getRowPosition(), "mhvsl", txt_hhvsl.getValue() );
            ds_ocMblhList.setCellData(ds_ocMblhList.getRowPosition(), "mhvyg", txt_hhvyg.getValue() );
            ds_ocMblhList.setCellData(ds_ocMblhList.getRowPosition(), "mhlodcd", ed_hhlodcd.getValue()  );  //Loading
            ds_ocMblhList.setCellData(ds_ocMblhList.getRowPosition(), "mhlodnm", txt_hhdiscnm.getValue()  );  //Loading
            ds_ocMblhList.setCellData(ds_ocMblhList.getRowPosition(), "mhdisccd", ed_hhdisccd.getValue() ); //Discharge
            ds_ocMblhList.setCellData(ds_ocMblhList.getRowPosition(), "mhdiscnm", txt_hhlodnm.getValue() ); //Discharge
            ds_ocMblhList.setCellData(ds_ocMblhList.getRowPosition(), "mhunit", txt_hhunit.getValue() ); //Unit
            ds_ocMblhList.setCellData(ds_ocMblhList.getRowPosition(), "inpid", scwin.userId);
        }
    }

    ds_houseblList.setCellData(0, "chk", "T");

    str1 = txt_hhs1.getValue();
    hhs = str1.split("\n");

    str2 = txt_hhc1.getValue();
    hhc = str2.split("\n");

    str3 = txt_hhn1.getValue();
    hhn = str3.split("\n");

    if(hhs[0].length > 100){
        alert("Shipper명을 100자리를 초과하여 입력하면 EDI전송이 안됩니다. 100자리 이하로 맞춰주세요 \n 현재 자리수 : "+hhs[0].length);
        txt_hhs1.focus();
        return false;
    }
    if(hhc[0].length > 100){
        alert("Consignee명을 100자리를 초과하여 입력하면 EDI전송이 안됩니다. 100자리 이하로 맞춰주세요 \n 현재 자리수 : "+hhc[0].length);
        txt_hhc1.focus();
        return false;
    }
    if(hhn[0].length > 100){
        alert("Notify명을 100자리를 초과하여 입력하면 EDI전송이 안됩니다. 100자리 이하로 맞춰주세요 \n 현재 자리수 : " +hhn[0].length);
        txt_hhn1.focus();
        return false;
    }

    //두줄이 글자가 쓰여있어야 EDI전송이 가능하므로 체크  sh1004dd
    if(hhs[0]=="\r" || hhs[0]==""|| hhs[1]=="\r" || hhs[1]=="" ){
        alert("Shipper명을 두 줄로 입력하지 않으면 EDI전송이 안됩니다. \n 두줄에 입력해주세요");
        txt_hhs1.focus();
        return false;
    }

    if(hhc[0]=="\r" || hhc[0]==""|| hhc[1]=="\r" || hhc[1]=="" ){
        alert("Consignee명을 두 줄로 입력하지 않으면 EDI전송이 안됩니다. \n 두줄에 입력해주세요");
        txt_hhc1.focus();
        return false;
    }

    // B/L PIC값이 없을때 등록자 아이디로 입력(PIC값이 null되는걸 방지)
    if(ed_blpic.getValue() == "" ) {
        txt_blpic.setValue("");
        ds_houseblList.setCellData(0, "pic", scwin.userId );
    }

    ds_houseblList.setCellData(0, "hhs1", hhs[0] == undefined ? "" : hhs[0].replace(/\r/gi,'').replace(/\n/gi,''));
    ds_houseblList.setCellData(0, "hhs2", hhs[1] == undefined ? "" : hhs[1].replace(/\r/gi,'').replace(/\n/gi,''));
    ds_houseblList.setCellData(0, "hhs3", hhs[2] == undefined ? "" : hhs[2].replace(/\r/gi,'').replace(/\n/gi,''));
    ds_houseblList.setCellData(0, "hhs4", hhs[3] == undefined ? "" : hhs[3].replace(/\r/gi,'').replace(/\n/gi,''));
    ds_houseblList.setCellData(0, "hhs5", hhs[4] == undefined ? "" : hhs[4].replace(/\r/gi,'').replace(/\n/gi,''));

    ds_houseblList.setCellData(0, "hhc1", hhc[0] == undefined ? "" : hhc[0].replace(/\r/gi,'').replace(/\n/gi,''));
    ds_houseblList.setCellData(0, "hhc2", hhc[1] == undefined ? "" : hhc[1].replace(/\r/gi,'').replace(/\n/gi,''));
    ds_houseblList.setCellData(0, "hhc3", hhc[2] == undefined ? "" : hhc[2].replace(/\r/gi,'').replace(/\n/gi,''));
    ds_houseblList.setCellData(0, "hhc4", hhc[3] == undefined ? "" : hhc[3].replace(/\r/gi,'').replace(/\n/gi,''));
    ds_houseblList.setCellData(0, "hhc5", hhc[4] == undefined ? "" : hhc[4].replace(/\r/gi,'').replace(/\n/gi,''));

    ds_houseblList.setCellData(0, "hhn1", hhn[0] == undefined ? "" : hhn[0].replace(/\r/gi,'').replace(/\n/gi,''));
    ds_houseblList.setCellData(0, "hhn2", hhn[1] == undefined ? "" : hhn[1].replace(/\r/gi,'').replace(/\n/gi,''));
    ds_houseblList.setCellData(0, "hhn3", hhn[2] == undefined ? "" : hhn[2].replace(/\r/gi,'').replace(/\n/gi,''));
    ds_houseblList.setCellData(0, "hhn4", hhn[3] == undefined ? "" : hhn[3].replace(/\r/gi,'').replace(/\n/gi,''));
    ds_houseblList.setCellData(0, "hhn5", hhn[4] == undefined ? "" : hhn[4].replace(/\r/gi,'').replace(/\n/gi,''));

    //Remark 엔터키 기준으로 나누어서 저장
    str4 = txt_hhrmk1.getValue();
    rmk = str4.split("\n");

    ds_houseblList.setCellData(0, "hhrmk1", rmk[0] == undefined ? "" : rmk[0].replace(/\r/gi,'').replace(/\n/gi,''));
    ds_houseblList.setCellData(0, "hhrmk2", rmk[1] == undefined ? "" : rmk[1].replace(/\r/gi,'').replace(/\n/gi,''));
    ds_houseblList.setCellData(0, "hhrmk3", rmk[2] == undefined ? "" : rmk[2].replace(/\r/gi,'').replace(/\n/gi,''));
    ds_houseblList.setCellData(0, "hhrmk4", rmk[3] == undefined ? "" : rmk[3].replace(/\r/gi,'').replace(/\n/gi,''));
    ds_houseblList.setCellData(0, "hhrmk5", rmk[4] == undefined ? "" : rmk[4].replace(/\r/gi,'').replace(/\n/gi,''));

    if(ed_shhcurdt.getValue() == "") {
        ds_houseblList.setCellData(0, "hhcurdt", ed_hheta.getValue());
    }

    if (lc_shhcucd.getValue() == "" ){
        lc_shhcucd.setValue("KRW");
    }

    // GPT에서 가져온 B/L인데, 기존에 동일한 B/L이 존재할 경우
    if (scwin.popUpResult != null && scwin.popUpResult[2] == 'Y' && cnd_ed_hhblno.getValue().trim() == scwin.popUpResult[0] && gptYn) {
        // 다이렉트 B/L일 경우, MHNO 재조회
        if (cnd_lc_autono.getValue()=="DIRECT") {
            scwin.f_MhnoLoading();
            ds_hmhno.setCellData(0, "code", temp_mhno);
        }
        var sbmResult = await $c.sbm.execute(sbm_ocrSave); if (scwin.sbm_tr_ocrSave_submitdone) { scwin.sbm_tr_ocrSave_submitdone(sbmResult); };
    }
    else {
        var sbmResult = await $c.sbm.execute(sbm_save); if (scwin.sbm_tr_save_submitdone) { scwin.sbm_tr_save_submitdone(sbmResult); }; // 실행
    }
}

scwin.f_sellingAmt = function (Row,Colid,olddata){
    if (ds_selling.getCellData(Row, "crcCd") == "KRW") {
        ds_selling.setCellData(Row, "sellAmt", Math.round(Number(ds_selling.getCellData(Row, "chgWt")) * Number(ds_selling.getCellData(Row, "sellUpr"))));
    }else if (ds_selling.getCellData(Row, "crcCd") == "JPY" || ds_selling.getCellData(Row, "crcCd") == "ITL"
    || ds_selling.getCellData(Row, "crcCd") == "IDR" || ds_selling.getCellData(Row, "crcCd") == "ESP" ) {
        ds_selling.setCellData(Row, "sellAmt", Math.round(Number(ds_selling.getCellData(Row, "sellAmtFcrc")) * Number(ds_selling.getCellData(Row, "exRate")))/100);
    }else{
        ds_selling.setCellData(Row, "sellAmt", Math.round(Number(ds_selling.getCellData(Row, "sellAmtFcrc")) * Number(ds_selling.getCellData(Row, "exRate"))));
    }
}

scwin.f_sellingAmtFcrc = function (Row,Colid,olddata){
    if (ds_selling.getCellData(Row, "crcCd") == "KRW") {
        ds_selling.setCellData(Row, "sellAmtFcrc", "0");
    }else{
        ds_selling.setCellData(Row, "sellAmtFcrc", Math.round((Number(ds_selling.getCellData(Row, "chgWt")) * Number(ds_selling.getCellData(Row, "sellUpr"))) * 100) / 100);
    }
}

scwin.f_SellingSum = function (){
    let v_SellingSumAmount = 0;
    let v_SellingSumAmountW = 0;
    let v_SellingSumVat = 0;
    let v_SellingSumAmountUs = 0;
    let v_SellingAmountSum = 0;
    for ( var i = 0; i< ds_selling.getRowCount(); i++) {
        if (ds_selling.getRowStatus(i) != "D") {
            v_SellingSumAmount += Number(ds_selling.getCellData(i, "sellAmtFcrc"));
            v_SellingSumAmountW += Number(ds_selling.getCellData(i, "sellAmt"));
            v_SellingSumVat += Number(ds_selling.getCellData(i, "vatAmt"));
            v_SellingSumAmountUs +=  Number(ds_selling.getCellData(i, "usdAmt"));
        }
    }

    ed_SellingSumAmount.setValue(v_SellingSumAmount);
    ed_SellingSumAmountW.setValue(v_SellingSumAmountW);
    ed_SellingSumVat.setValue(v_SellingSumVat);
    ed_SellingSumAmountUs.setValue(v_SellingSumAmountUs);
    v_SellingAmountSum = v_SellingSumAmountW + v_SellingSumVat;
    ed_SellingAmountSum.setValue(v_SellingAmountSum);
}

