scwin.f_validate = async function () {
    // VALIDATE
    if(!$c.gus.cfValidate([ed_hhetd,ed_hhondt,ed_hheta,ed_hhisudt,ed_creadyDt])){  //validExp 가 yes일때 check
        return false;
    }


    if (ed_hheta.getValue() == "") {
        $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["ETA"]); //@는 필수입력항목입니다.
        tab_main.setSelectedTabIndex(0);  // 1번째 탭으로 이동.  cnd_ed_hhblno.focus() 잡아주기 위함.
        ed_hheta.focus();
        return false;
    }


    //ETD-ETA가 저장하는 날짜로 부터 3개월 이상의 미래일 수 없다.    
    if( $c.gus.cfMonthsBetween(scwin.strCurDate.toDate(), ed_hhetd.getValue().toDate() )  > 3){
        alert("ETD가 저장하는 날짜로 부터 3개월 이상의 미래일 수 없습니다.");
        tab_main.setSelectedTabIndex(0);  // 1번째 탭으로 이동.  cnd_ed_hhblno.focus() 잡아주기 위함.
        ed_hhetd.focus();
        return false;
    }

    //ETD-ETA가 저장하는 날짜로 부터 3개월 이상의 미래일 수 없다.
    if( $c.gus.cfMonthsBetween(scwin.strCurDate.toDate(), ed_hheta.getValue().toDate() )  > 3){
        alert("ETA가 저장하는 날짜로 부터 3개월 이상의 미래일 수 없습니다.");
        tab_main.setSelectedTabIndex(0);  // 1번째 탭으로 이동.  cnd_ed_hhblno.focus() 잡아주기 위함.
        ed_hheta.focus();
        return false;
    }

    //ETD-ETA가 3년 이상의 과거 일 수 없다.
    if( $c.gus.cfYearsBetween(ed_hhetd.getValue().toDate(), scwin.strCurDate.toDate())  > 3){
        alert("ETD가 3년 이상의 과거 일 수 없습니다.");
        tab_main.setSelectedTabIndex(0);  // 1번째 탭으로 이동.  cnd_ed_hhblno.focus() 잡아주기 위함.
        ed_hhetd.focus();
        return false;
    }

    //ETD-ETA가 3년 이상의 과거 일 수 없다.
    if( $c.gus.cfYearsBetween(ed_hheta.getValue().toDate(), scwin.strCurDate.toDate())  > 3){
        alert("ETA가 3년 이상의 과거 일 수 없습니다.");
        tab_main.setSelectedTabIndex(0);  // 1번째 탭으로 이동.  cnd_ed_hhblno.focus() 잡아주기 위함.
        ed_hheta.focus();
        return false;
    }


    //ETA-ETD(transit time)가 150일을 초과할 수 없다.  *150일(총 운항DATE 수) : ETA날짜에서 ETD날짜를 빼고 +1 한 날짜
    if( WebSquare.date.dateDiff(ed_hhetd.getValue(), ed_hheta.getValue())  > 149){
        alert("ETA-ETD(transit time)가 150일을 초과할 수 없습니다.");
        tab_main.setSelectedTabIndex(0);  // 1번째 탭으로 이동.  cnd_ed_hhblno.focus() 잡아주기 위함.
        ed_hhetd.focus();
        return false;
    }


    //EDI ITEM 필수값 체크 - 20/02/18 현업요청으로 저장시, 필수값 체크 넣었으나 다시 빼달라는 요청으로 주석처리.
    if (txt_hhmitem2.getValue() == "") {
        $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["EDI ITEM"]);  //@은(는) 보다 작아야 합니다.
        tab_main.setSelectedTabIndex(0);  // 1번째 탭으로 이동.  cnd_ed_hhblno.focus() 잡아주기 위함.
        txt_hhmitem2.focus();
        return false;
    }

    if(ed_hhbuyer.getValue() == "") {
        $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Department"]); //@는 필수입력항목입니다.
        tab_main.setSelectedTabIndex(0);  // 1번째 탭으로 이동.  cnd_ed_hhblno.focus() 잡아주기 위함.
        ed_hhbuyer.focus();
        return false;
    }

    //EDI ITEM 글자수 및 특수문자 여부 CHECK
    if(!ilcommon.cf_ChkInputOnlyNumberAndAlphabet(txt_hhmitem2.getValue())) {
        alert("EDI ITEM에 특수문자만 입력은 불가능합니다.");
        return false;
    }

    if( $c.gus.cfGetByteLength(txt_hhmitem2.getValue())<2){
        alert("EDI ITEM에 2글자 이상을 입력하셔야합니다.");
        return false;
    }

    if(lc_contractno.getValue() == ""){
        alert("계약은 필수항목 입니다. Customer를 확인하세요."); //@는 필수입력항목입니다.
        tab_main.setSelectedTabIndex(0);  // 1번째 탭으로 이동.
        ed_hhactcust.focus();
        return false;
    }


    var url = "/cm.zz.RetrieveComboCMD.do?sysCd=ilCommonEBC&queryId=retriveCustomerInfo&param1=" + ed_hhactcust.getValue().trim();
    await scwin._execDataId(ds_customerInfo, url);    
    if( ds_customerInfo.getRowCount() > 0){
        if( ed_hhbuyer.getValue() != ds_customerInfo.getCellData(ds_customerInfo.getRowPosition(), "col1") ){
            $c.gus.cfAlertMsg(scwin.MSG_LO_WRN_007);
            tab_main.setSelectedTabIndex(0);
            ed_hhbuyer.focus();
            return false;
        }
    }

    // Buying Inner Dept
    // type 값 Internal 선택 시, Inner Dept은 필수 입력 될 수 있도록.
    for ( var i = 0; i< ds_buying.getRowCount(); i++) {
        if(ds_buying.getCellData(i, "pchsTyp") == "3" && ds_buying.getCellData(i, "sellDeptCd") == "" ){
            $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Inner Department"]); //@는 필수입력항목입니다.
            gr_buying.focus();
            var rowIdx = ds_buying.getRowPosition();
            gr_buying.setFocusedCell((rowIdx == null ? 0 : rowIdx), "sellDeptCd", true); // forcus
            return false;
        }
    }

    // Buying Unit
    for ( var i = 0; i< ds_buying.getRowCount(); i++) {
        if(ds_buying.getCellData(i, "fareUnit") == ""){
            $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Unit"]); //@는 필수입력항목입니다.
            gr_buying.focus();
            var rowIdx = ds_buying.getRowPosition();
            gr_buying.setFocusedCell((rowIdx == null ? 0 : rowIdx), "fareUnit", true); // forcus
            return false;
        }
    }

    // B/L type 필수 입력
    if (cnd_lc_autono.getValue() == "" || cnd_lc_autono.getValue() == null) {
        $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["B/L Type"]); //@는 필수입력항목입니다.
        return false;
    }

    return true;
}

scwin.f_validate_freight = function (){ //저장전 fregiht list 유효성 CHECK
    // VALIDATE    
    if(!$c.gus.cfValidate([gr_selling,gr_partner,gr_buying])){  //validExp 가 yes일때 check
        return false;
    }

    for (var i =0; i<ds_selling.getRowCount(); i++){
        if(ds_selling.getCellData(i, "fareEngCd") == "" && ds_selling.getCellData(i, "sellAmt") == 0 ) {
            // F/CODE공란이고 AMOUNT(W)값 0이면 해당행 삭제
            ds_selling.removeRow(i);
        }

        if(ds_selling.getCellData(i, "fareEngCd") !="" && ds_selling.getCellData(i, "sellAmt") == 0 ) {
            // F/CODE있고 AMOUNT(W)값이 0이면 경고 팝업
            alert("Amount(W) 금액이 0입니다. \nSelling List "+i+"번째 데이터를 확인하세요.");
            return false;
        }
        //삭제 시 내부거래 체크
        if(ds_selling.getRowStatus(i) == "D" ) {
            scwin.f_postDtChk(ds_selling.getCellData(i, "odrNo"),ds_selling.getCellData(i, "sellSeq"),ds_selling.getCellData(i, "kcomcd"),ds_selling.getCellData(i, "seaAirCls"),ds_selling.getCellData(i, "blNo"),ds_selling.getCellData(i, "mhno"));
            var isPostDt = postDtDataSet_.getCellData(0,"col1");

            if(isPostDt != "" ){
                alert("내부거래 확정 건 입니다. \nSelling List "+i+"번째 데이터를 확인하세요.");
                return false;
            }
        }
    }


    for (var i =0; i< ds_partner.getRowCount(); i++){
        if(ds_partner.getCellData(i, "fareEngCd") == "" && ds_partner.getCellData(i, "sellAmt") == 0 ) {
            // F/CODE공란이고 AMOUNT(W)값 0이면 해당행 삭제
            ds_partner.removeRow(i);
        }

        if(ds_partner.getCellData(i, "fareEngCd") !="" && ds_partner.getCellData(i, "sellAmt") == 0 ) {
            // F/CODE있고 AMOUNT(W)값이 0이면 경고 팝업
            alert("Amount(W) 금액이 0입니다. \nPartner List "+i+"번째 데이터를 확인하세요.");
            return false;
        }
        //삭제 시 내부거래 체크
        if(ds_partner.getRowStatus(i) == "D" ) {
            scwin.f_postDtChk(ds_partner.getCellData(i, "odrNo"),ds_partner.getCellData(i, "sellSeq"),ds_partner.getCellData(i, "kcomcd"),ds_partner.getCellData(i, "seaAirCls"),ds_partner.getCellData(i, "blNo"),ds_partner.getCellData(i, "mhno"));
            var isPostDt = postDtDataSet_.getCellData(0,"col1");

            if(isPostDt != "" ){
                alert("내부거래 확정 건 입니다. \nPartner List "+i+"번째 데이터를 확인하세요.");
                return false;
            }
        }
    }


    for (var i =0; i< ds_buying.getRowCount(); i++){
        if(ds_buying.getCellData(i, "fareEngCd") == "" && ds_buying.getCellData(i, "pchsAmt") == 0 ) {
            // F/CODE공란이고 AMOUNT(W)값 0이면 해당행 삭제
            ds_buying.removeRow(i);
        }

        if(ds_buying.getCellData(i, "fareEngCd") !="" && ds_buying.getCellData(i, "pchsAmt") == 0 ) {
            // F/CODE있고 AMOUNT(W)값이 0이면 경고 팝업
            alert("Amount(W) 금액이 0입니다. \nBuying List "+i+"번째 데이터를 확인하세요.");
            return false;
        }

        //삭제 시 내부거래 체크
        if(ds_buying.getRowStatus(i) == "D" ) {
            scwin.f_postDtChk(ds_buying.getCellData(i, "odrNo"),ds_buying.getCellData(i, "pchsSeq"),ds_buying.getCellData(i, "kcomcd"),ds_buying.getCellData(i, "seaAirCls"),ds_buying.getCellData(i, "blNo"),ds_buying.getCellData(i, "mhno"));
            var isPostDt = postDtDataSet_.getCellData(0,"col1");

            if(isPostDt != "" ){
                alert("내부거래 확정 건 입니다. \nbuying List "+i+"번째 데이터를 확인하세요.");
                return false;
            }
        }
    }


    //영세코드 사용시 부가세 입력 제한
    //VAT 금액  Amount(W)금액의 10%
    for ( var i = 0; i< ds_selling.getRowCount(); i++) {
        if(ds_selling.getCellData(i, "vatYn") == 0){
            if (ds_selling.getCellData(i, "vatAmt") > 0){
                alert("영세코드와 부가세 금액은 함께 입력될 수 없습니다. \nSelling List "+i+"번째 데이터를 확인하세요.");
                gr_selling.focus();
                var rowIdx = ds_selling.getRowPosition();
                gr_selling.setFocusedCell((rowIdx == null ? 0 : rowIdx), "vatAmt", true);
                return false;
            }
        }

        if(ds_selling.getCellData(i, "vatYn") == 1){
            if(Math.abs(Math.round(Number(ds_selling.getCellData(i, "sellAmt")) * 0.1) - Number(ds_selling.getCellData(i, "vatAmt"))) >1){
                alert("VAT 금액은 Amount(W)금액의 10%입니다. \nSelling List "+i+"번째  VAT 금액을 확인하세요.");
                gr_selling.focus();
                var rowIdx = ds_selling.getRowPosition();
                gr_selling.setFocusedCell((rowIdx == null ? 0 : rowIdx), "vatAmt", true);
                return false;
            }
        }

    }


    for ( var i = 0; i< ds_buying.getRowCount(); i++) {
        if(ds_buying.getCellData(i, "vatYn") == 0){
            if (ds_buying.getCellData(i, "vat") > 0){
                alert("영세코드와 부가세 금액은 함께 입력될 수 없습니다. \nBuying List "+i+"번째 데이터를 확인하세요.");
                gr_buying.focus();
                var rowIdx = ds_buying.getRowPosition();
                gr_buying.setFocusedCell((rowIdx == null ? 0 : rowIdx), "vatAmt", true);
                return false;
            }
        }
    }

    return true;

}

scwin.ISO6346Check = function (con) {
    if (!con || con == "" || con.length != 11) { return false; }
    con = con.toUpperCase();
    var re = /^[A-Z]{4}\d{7}/;

    if (re.test(con)) {
        var sum = 0;
        for (i = 0; i < 10; i++) {
            var n = con.substr(i, 1);
            if (i < 4) {
                n = "0123456789A?BCDEFGHIJK?LMNOPQRSTU?VWXYZ".indexOf(con.substr(i, 1));
            }
            n *= Math.pow(2, i);
            sum += n;
        }

        if (con.substr(0, 4) == "HLCU") {
            sum -= 2;
        }

        sum %= 11;
        sum %= 10;
        return sum == con.substr(10);
    }else{
        return false;
    }
}

