scwin.ds_selling_oncelldatachange = function (info) {
    const colid = info.colID;
    const newValue = String(info.newValue == null ? "" : info.newValue).trim();
    const row = info.rowIndex;

    if (colid == "crcCd") {
        if (!$c.util.isEmpty(newValue)) {
            var found = false;
            for (var ci = 0; ci < ds_currencyCode.getRowCount(); ci++) {
                if (ds_currencyCode.getCellData(ci, "code") == newValue) {
                    found = true;
                    break;
                }
            }
            if (!found) {
                ds_selling.setCellData(row, "exRate", "");
                $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ["Currency Information"]);
            } else {
                if (newValue != "KRW") {
                    scwin.f_ExRateSellingGridLoading();
                }
            }
        } else {
            return;
        }
    }

    // sum값 call    
    if (colid == "sellAmtFcrc" || colid == "sellAmt" || colid == "vatAmt") {
        scwin.f_SellingSum();
    }
};

scwin.ds_partner_oncelldatachange = function (info) {
    var rowIndex = info.rowIndex;
    var colId = info.colId || info.columnId;
    if (colId == "crcCd") {
        var crcCd = ds_partner.getCellData(rowIndex, "crcCd");
        if (crcCd != "") {
            var str = scwin._valueRow(ds_currencyCode, "code", crcCd);
            if (str == "0") {
                ds_partner.setCellData(rowIndex, "exRate", "");
                $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ["Currency Information"]);
            } else {
                if (crcCd != "KRW") {
                    scwin.f_ExRatePartnerGridLoading();
                }
            }
        } else {
            return;
        }
    }
    if (colId == "sellAmtFcrc" || colId == "sellAmt") {
        scwin.f_PartnerSum();
    }
};

scwin.ds_buying_oncelldatachange = function (info) {
    var rowIndex = info.rowIndex;
    var colId = info.colId || info.columnId;
    if (colId == "crcCd") {
        var crcCd = ds_buying.getCellData(rowIndex, "crcCd");
        if (crcCd != "") {
            var str = scwin._valueRow(ds_currencyCode, "code", crcCd);
            if (str == "0") {
                ds_buying.setCellData(rowIndex, "exRate", "");
                $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ["Currency Information"]);
            } else {
                if (crcCd != "KRW") {
                    scwin.f_ExRateBuyingGridLoading();
                }
            }
        } else {
            return;
        }
    }
    if (colId == "pchsAmtFcrc" || colId == "pchsAmt" || colId == "vat") {
        scwin.f_BuyingSum();
    }
};

