scwin.gr_buying_ontextimageclick = function(rowIndex, columnIndex) {
    var colId = gr_buying.getColumnID(columnIndex);
    switch (colId) {
        case "pchsClntNo":
            scwin.f_PopUpGrid("BuyingCustomer", rowIndex, "F", "F", "F");
            break;
        case "fareEngCd":
            scwin.f_PopUpGrid("BuyingFcode", rowIndex, "F", "F", "F");
            break;
        case "rsltsStdDt":
            //if ($c.gus.cfOpenCalendar) $c.gus.cfOpenCalendar(gr_buying, rowIndex, colId);
            break;
        case "sellDeptCd":
            scwin.f_PopUpGrid("BuyingDept", rowIndex, "F", "F", "F");
            break;
        default:
            break;
    }
};

scwin.gr_buying_oncloseup = function(rowIndex, columnIndex, value) {
    var colId = gr_buying.getColumnID(columnIndex);
    switch (colId) {
        case "fareUnit":
        scwin.f_packageRateBuyingLoading(rowIndex + 1, colId);
        scwin.f_buyingTariffRateLoading();
        break;
        case "pchsTyp":
        if (ds_buying.getCellData(ds_buying.getRowPosition(), "pchsTyp") == "3") {
            ds_buying.setCellData(ds_buying.getRowPosition(), "pchsClntNo", scwin.p_clntNo || "");
            ds_buying.setCellData(ds_buying.getRowPosition(), "pchsClntNm", "");
            scwin.f_PopUpGrid("BuyingCustomer", rowIndex + 1, "T", "F", "F");
        }else{
            ds_buying.setCellData(ds_buying.getRowPosition(), "pchsClntNo", "");
            ds_buying.setCellData(ds_buying.getRowPosition(), "pchsClntNm", "");
        }
        break;
        default:
        break;
    }
};


scwin.gr_buying_onbeforeedit = function (rowIndex, columnIndex, value) {
    var colId = gr_buying.getColumnID(columnIndex);
    if (colId == "fareUnit") {
        scwin.f_buyingUnitLoading();
    }
};

scwin.gr_buying_onviewchange = function(info) {    //rowIndex, columnIndex, value
    let row = info.rowIndex;
    let col = info.colId;
    let olddata = info.oldValue;
    let value = info.newValue;    
    if(row < 0 || ds_buying.getRowCount() <= row) return;

    switch(col){
        case "pchsClntNo":
            if(!$c.util.isEmpty(value)){
                ds_buying.setCellData(row,"pchsClntNm","");
                scwin.f_PopUpGrid("BuyingCustomer", row, "T", "F", "F");
            } else {
                ds_buying.setCellData(row, "pchsClntNo","");
                ds_buying.setCellData(row, "pchsClntNm","");
            }
            break;

        case "fareEngCd":
            if(!$c.util.isEmpty(value)){
                ds_buying.setCellData(row,"fareEngNm","");
                scwin.f_PopUpGrid("BuyingFcode", row, "T", "F", "F");
            } else {
                ds_buying.setCellData(row, "fareEngCd","");
                ds_buying.setCellData(row, "fareEngNm","");
            }

            if(ds_buying.getCellData(row,"pchsTyp") == "3"){
                if( ds_buying.getCellData(row,"fareEngCd") == "TRD"){
                    scwin.f_BuyingDeptLoading(row);
                }
            }

            if(scwin.v_linkcheck == "" || scwin.v_linkcheck != 9){
                scwin.f_buyingAmtFcrc(row,col,olddata);
                scwin.f_buyingAmt(row,col,olddata);
                scwin.f_buyingVat(row,col,olddata);
                scwin.f_buyingUsdAmt(row,col,olddata);
            }
            break;

        case "sellDeptCd":
            if(!$c.util.isEmpty(value)){
                ds_buying.setCellData(row,"sellDeptNm","");
                scwin.f_PopUpGrid("BuyingDept", row, "T", "F", "F");
            } else {
                ds_buying.setCellData(row,"sellDeptCd","");
                ds_buying.setCellData(row,"sellDeptNm","");
            }
            break;

        case "crcCd":
        case "chgWt":
        case "pchsUpr":
            scwin.f_buyingAmtFcrc(row,col,olddata);
            scwin.f_buyingAmt(row,col,olddata);
            scwin.f_buyingVat(row,col,olddata);
            scwin.f_buyingUsdAmt(row,col,olddata);
            break;

        case "exRate":
            scwin.f_buyingAmt(row,col,olddata);
            break;

        case "pchsAmt":
            scwin.f_buyingVat(row,col,olddata);
            break;

        case "vat":
            scwin.f_buyingUsdAmt(row,col,olddata);
            break;

        case "fareUnit": // gr_buying  OnCloseUp(Row,Colid)
            scwin.f_packageRateBuyingLoading(row, col);
            scwin.f_buyingTariffRateLoading();	
            break;	

        case "pchsTyp": // gr_buying  OnCloseUp(Row,Colid)
            // 내부부서일때 원본 로직 유지
            var pchsTyp = value;
            if(pchsTyp == "3"){
                ds_buying.setCellData(row, "pchsClntNo", scwin.v_clntNo);
                ds_buying.setCellData(row, "pchsClntNm", "");
                scwin.f_PopUpGrid("BuyingCustomer", row, "T", "F", "F");
            } else {
                ds_buying.setCellData(row, "pchsClntNo", "");
                ds_buying.setCellData(row, "pchsClntNm", "");
            }
        break;	  	  
    }
};

