scwin.gr_ocContList_oneditend = function(rowIndex, columnIndex, value) {
    var colId = gr_ocContList.getColumnID(columnIndex);
    if ($c.str.trim(ds_ocContList.getCellData(rowIndex, "mctype")) != "") {
        var str = scwin._valueRow(ds_containerType, "code", ds_ocContList.getCellData(rowIndex, "mctype"));
        if (str === "0") {
            $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ["Container Type"]);
            gr_ocContList.focus();
            var rowIdx =ds_ocContList.getRowPosition();
            gr_ocContList.setFocusedCell((rowIdx == null ? 0 : rowIdx), "mctype", true);
            return;
        }
    }

    var rowCount = ds_ocContList.getRowCount();
    for (var i = 0; i < rowCount ; i++) {
        for (var j = i + 1; j < rowCount; j++) {
            var v1 = ds_ocContList.getCellData(i, "mccntno") || "";
            var v2 = ds_ocContList.getCellData(j, "mccntno") || "";
            if (v1 === "" && v2 === "") continue;
            if (String(v1) === String(v2)) {
                $c.gus.cfAlertMsg(E_MSG_CM_ERR_032, ["Container"]);
                gr_ocContList.focus();
                return;
            }
        }
    }

    if (rowIndex >= 0 && ds_ocContList.getRowCount() > rowIndex) {
        switch (colId) {
            case "mctype":
            if ($c.str.trim(ds_ocContList.getCellData(rowIndex, colId)) != "") {
                scwin.f_PopUpGrid("mctype", rowIndex, "T");
            }else{
                ds_ocContList.setCellData(rowIndex, "mctype", "");
            }
            break;
            case "mcpkgcd":
            if ($c.str.trim(ds_ocContList.getCellData(rowIndex, colId)) != "") {
                scwin.f_PopUpGrid("mcpkgcd", rowIndex, "T");
            }else{
                ds_ocContList.setCellData(rowIndex, "mcpkgcd", "");
            }
            break;
            default:
            break;
        }
    }
};

scwin.gr_ocContList_onviewchange = async function (info) {
    const row = info.rowIndex;
    const colid = info.colId;
    const olddata = info.oldValue;

    if (!$c.util.isEmpty(ds_ocContList.getCellData(row, "mctype"))) {
        var STR = ds_containerType.getMatchedData("code", ds_ocContList.getCellData(row, "mctype"));
        if (STR.length < 1) {  // 값이 없을때 == 0
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ["Container Type"]); //  @이(가) 존재하지 않습니다.
            gr_ocContList.focus();
            gr_ocContList.setFocusedCell(row, "mctype", false);

        } else {
            return true;
        }
    }

    switch (colid) {    
        case "mccntno": // 3269
            for (var i = 0; i < ds_ocContList.getRowCount() - 1; i++) {
                for (var j = i + 1; j <= ds_ocContList.getRowCount(); j++) {

                    var v1 = ds_ocContList.getCellData(i, "mccntno");
                    var v2 = ds_ocContList.getCellData(j, "mccntno");

                    // AUTO 생성 시(둘 다 빈값이면 skip)
                    if ($c.util.isEmpty(v1) && $c.util.isEmpty(v2)) {
                        continue;
                    }

                    if (v1 === v2) {
                        $c.gus.cfAlertMsg(E_MSG_CM_ERR_032, ["Container"]); // @은(는) 중복될 수 없습니다.

                        // 그리드 포커스 + 컬럼 포커스
                        gr_ocContList.focus();
                        gr_ocContList.setFocusedCell(j, "mccntno", true);
                        return;
                    }
                }
            }

            break;

        case "mctype":
            //코드값이 공백이 아닌경우 && 값이 변하였을경우 팝업을 호출한다.
            if (!$c.util.isEmpty(ds_ocContList.getCellData(row, colid))) {
                scwin.f_PopUpGrid("mctype", row, "T");
                //Name field 존재시 check.
                //Name Value 가 Blank 일경우 코드값을 Blank 한다.
            } else { // if(ds_ocContList.NameValue(Row,Colid).trim() == "") {
                ds_ocContList.setCellData(row, "mctype", "");
                //ds_ocContList.NameValue(Row,"transnm") = "";
            }
            break;

        case "mcpkgcd":
            //코드값이 공백이 아닌경우 && 값이 변하였을경우 팝업을 호출한다.
            if (!$c.util.isEmpty(ds_ocContList.getCellData(row, colid))) {
                //ds_bulkDoorOrder.NameValue(Row,"transcd") = "";
                scwin.f_PopUpGrid("mcpkgcd", row, "T");
                //Name field 존재시 check.
                //Name Value 가 Blank 일경우 코드값을 Blank 한다.
            } else { // if(ds_ocContList.NameValue(Row,Colid).trim() == "") {
                ds_ocContList.setCellData(row, "mcpkgcd", "");
                //ds_containerDoorOrder.NameValue(Row,"transnm") = "";
            }
            break;

        default:
            break;
    }
};

