scwin.sbm_tr_retrieve_submitdone = async function(e) {    
    scwin.gptYn = false;
    txt_totalSelling.setValue(ds_selling.getRowCount());
    txt_totalPartner.setValue(ds_partner.getRowCount());
    txt_totalBuying.setValue(ds_buying.getRowCount());

	if(ds_houseblList.getRowCount() == 0){
		$c.gus.cfAlertMsg(E_MSG_CM_ERR_003); //  해당되는 자료가 존재하지 않습니다
		scwin.f_Set("INIT");
		scwin.f_Check(); // Object Check
	}else{
		ds_houseblList.setRowPosition(0);
		ed_totcnt.setValue(ds_ocContList.getRowCount()); // 조회된 건수를Grid 하단에 표시한다.
		var v_totPkg = 0;
		var v_totWgt = 0;
		var v_totMsr = 0;
		for (var i = 0; i < ds_ocContList.getRowCount(); i++){
			v_totPkg +=Number(ds_ocContList.getCellData(i, "mcpkg"));
			v_totWgt +=Number(ds_ocContList.getCellData(i, "mcwgt"));
			v_totMsr +=Number(ds_ocContList.getCellData(i, "mcmsr"));
		}
		ed_totpkg.setValue(v_totPkg);
		ed_totwgt.setValue(v_totWgt);
		ed_totmsr.setValue(v_totMsr);
		scwin.f_invoiceCheck(); // invoice Check
		scwin.f_Set("RETRIEVE");


        // Booking seq combo 값 세팅
        if (ds_bkseq.getRowCount() === 0) {
            ds_bkseq.insertRow(0);
        }        
		ds_bkseq.setCellData(ds_bkseq.getRowPosition(), "code", ds_houseblList.getCellData(0, "hhbkgseq"));		
        lc_hhbkgseq.setValue(ds_bkseq.getCellData(0, "code"));

		scwin.f_ContractInfo();

		$c.gus.cfEnableObj(cnd_ed_hhblno, true);
		$c.gus.cfEnableObj(cnd_lc_mhno, true);

		ds_profit.removeAll();
		await $c.sbm.execute(sbm_retrieveProfit);
		ds_profit.setRowPosition(0);

		var sbmResult = await $c.sbm.execute(sbm_retrieve1);
		if (scwin.sbm_tr_retrieve1_submitdone) { scwin.sbm_tr_retrieve1_submitdone(sbmResult); }
		// await $c.sbm.execute(sbm_retrieveCtrtClnt);

	//	await $c.win.alert(scwin.hd_kcomcd);
		dma_retrieveCtrtClnt.set("kcomcd", scwin.hd_kcomcd);  
		dma_retrieveCtrtClnt.set("bkNo", ed_hhbkgno.getValue()); 
		await $c.sbm.execute(sbm_ctrtRetrieve);
		scwin.f_setFileUpDownFrame();
	}
};

scwin.sbm_retrieve1_submitdone = async function(e) {    
    if(ds_houseblList.getRowCount() == 0){	
