scwin.sbm_retrieveSelling_submitdone = async function(e) {           
    for (var i = 0; i < ds_selling.getRowCount(); i++){
        if ($c.util.isEmpty(ds_selling.getCellData(i, "bilgClntNo"))) {
            ds_selling.setCellData(i, "bilgClntNo", ed_hhactcust.getValue());
        }
        if ($c.util.isEmpty(ds_selling.getCellData(i, "bilgClntNm"))) {
            ds_selling.setCellData(i, "bilgClntNm", txt_hhactcustnm.getValue());
        }
        if (ds_sellingUnit.getRowCount() > 0) {
            ds_selling.setCellData(i, "fareUnit", ds_sellingUnit.getCellData(0, "code"));
        }            
        if(ds_selling.getCellData(i, "fareUnit") == ed_hhcnt1type.getValue()){
            if(ed_hhcnt1.getValue() > 0){
                ds_selling.setCellData(i, "chgWt", ed_hhcnt1.getValue());
            }
        } 
        if(ds_selling.getCellData(i, "fareUnit") == ed_hhcnt2type.getValue()){
            if(ed_hhcnt2.getValue() > 0){
                ds_selling.setCellData(i, "chgWt", ed_hhcnt2.getValue());
            }
        } 
        if(ds_selling.getCellData(i, "fareUnit") == ed_hhcnt3type.getValue()){
            if(ed_hhcnt3.getValue() > 0){
                ds_selling.setCellData(i, "chgWt", ed_hhcnt3.getValue());
            }
        } 
        if ($c.util.isEmpty(ds_selling.getCellData(i, "rsltsStdDt"))) {
            ds_selling.setCellData(i, "rsltsStdDt", $c.date.addDate(scwin.strCurDate, 1));
        }                
    }    
}

