scwin.sbm_retrieveOcr_submitdone = async function(e) {
    if(ds_houseblList.getRowCount() == 0){
		$c.gus.cfAlertMsg(E_MSG_CM_ERR_003); //  해당되는 자료가 존재하지 않습니다
		scwin.f_Set("INIT");
		scwin.f_Check(); // Object Check
		return;
	}

	var dsHouseblList_export = ds_houseblList.getAllJSON();
	var dsOcContList_export = ds_ocContList.getAllJSON();

	var temps = txt_hhs1.getValue();
	var tempc = txt_hhc1.getValue();
	var tempn = txt_hhn1.getValue();

	scwin.f_Create();

	lc_hhbkgseq.initAutoComplete();
	ds_houseblList.removeAll();
	ds_houseblList.setJSON(dsHouseblList_export);
    ds_houseblList.setRowPosition(0);
	ds_ocContList.removeAll();
	ds_ocContList.setJSON(dsOcContList_export);
    ds_ocContList.setRowPosition(0);

	cnd_ed_hhblno.setValue(ds_houseblList.getCellData(ds_houseblList.getRowPosition(), "hhblno"));

   	lc_hhcoload.setValue("N");					// Co-Load
   	ed_hhobl.setValue("3");					// O B/L
   	chb_hhtriange.setValue(false);			// Triangle
   	chb_hhnomi.setValue(false);				// NOMI
   	rd_hhdanggb.setValue("N");			// Dangerous
   	rd_hhmnfgb.setValue("I");				// Other -> Shipment Type
   	rd_hhcnrggb.setValue("C");			// Other -> Consignee
   	rd_hhntrggb.setValue("C");			// Other -> Notify
   	lc_hhwaregb.setValue("C");					// Other -> Allocation  setIndex

	lc_shhcucd.setValue("USD");
	lc_phhcucd.setValue("USD");
	lc_bhhcucd.setValue("USD");		

	await scwin.f_ContractInfo();    
	await scwin.f_MhnoLoading();

	ed_blpic.setValue(scwin.empNo);
	scwin.f_PopUp("B/L PIC", "T");

	txt_hhs1.setValue(temps);
	txt_hhc1.setValue(tempc);
	txt_hhn1.setValue(tempn);
	scwin.gptYn = true;

	scwin.f_setFileUpDownFrame();
};

