		//ds_buying.setCellData(i, "pchsClntNo", ed_hhliner.getValue()); 
		//ds_buying.setCellData(i, "pchsClntNm", txt_hhlinernm.getValue());   //Liner name		
		// scwin.f_buyingUnitLoading();
		//ds_buying.setCellData(row, "fareUnit", Number(ds_buyingUnit.getCellData(0, "code")));
		//scwin.f_packageRateBuyingLoading(row,'');	
		//if(Number(ds_houseblList.getCellData(ds_houseblList.getRowPosition()), "hhbltype") == "L")	{	
		//	ds_buying.setCellData(row, "fareUnit", "R/T");
		//	scwin.f_packageRateBuyingLoading(row,'');
