// 파일 업로드
scwin.saveFile = async function() {            
    //udc_attchedFileList.getData();    
	if(!await $c.win.confirm("B/L No: " + dma_attachedFile.get("blno") + "\n\n파일을 저장 하시겠습니까?")) {
		return;
	}

    scwin.fn_deleteFile();                  //파일삭제
    udc_attchedFileList.startFileUpload();  //파일업로드
};

//파일삭제
scwin.fn_deleteFile = async function () {    
    let fileList =  udc_attchedFileList.getData();    
    ds_fileDeleteGDS.removeAll();
    for (let idx in fileList) {
        let chk = fileList[idx].chk;
        if(chk == "1") {
            let row = ds_fileDeleteGDS.insertRow();                        
            ds_fileDeleteGDS.setRowJSON(row, fileList[idx], true);
            ds_fileDeleteGDS.setCellData(row, "fileName", fileList[idx].ORIGIN_FILE_NM);        
            ds_fileDeleteGDS.setCellData(row, "filePath", fileList[idx].FILE_STORED_PATH + fileList[idx].STORED_FILE_NM);
            ds_fileDeleteGDS.setCellData(row, "fileSize", fileList[idx].FILE_SIZE);   
            ds_fileDeleteGDS.setCellData(row, "houseNo", dma_attachedFile.get("houseNo"));

            //fileseq 찾기
            let arrJson = ds_attachedFileList.getMatchedJSON("filePath", fileList[idx].FILE_STORED_PATH);
            if (arrJson.length > 0){
                 ds_fileDeleteGDS.setCellData(row, "fileSeq", arrJson[0].fileSeq);  
            }       
        }        
    }

    if (ds_fileDeleteGDS.getRowCount() > 0) {
        await $c.sbm.execute(sbm_deleteFile);
    }
};

//업로드 후 DB처리
scwin.udc_attchedFileList_onFileUploadDone = async function (isSuccess) {    
    if(!isSuccess) return;    
    ds_fileUploadGDS.removeAll();    
    let fileList = udc_attchedFileList.getData();
    for (let idx in fileList) {
        let status = fileList[idx].status;
        if(status == "Completed") {
            let row = ds_fileUploadGDS.insertRow();                        
            ds_fileUploadGDS.setRowJSON(row, fileList[idx], true);
            ds_fileUploadGDS.setCellData(row, "fileName", fileList[idx].ORIGIN_FILE_NM);        
            ds_fileUploadGDS.setCellData(row, "filePath", fileList[idx].FILE_STORED_PATH + fileList[idx].STORED_FILE_NM);
            ds_fileUploadGDS.setCellData(row, "fileSize", fileList[idx].FILE_SIZE);                 
            ds_fileUploadGDS.setCellData(row, "fileSize", fileList[idx].FILE_SIZE);                 
        }
    }        

    if (ds_fileUploadGDS.getRowCount() > 0) {
        await $c.sbm.execute(sbm_saveFile);
    }
};

