scwin.ed_hhccd_onviewchange = function (info) {
    const newValue = info.newValue;
    const oldValue = info.oldValue;    

    if (scwin.statusFlag === "C" || scwin.statusFlag === "U") { // 신규
        if (oldValue != newValue) {
            txt_hhc1.setValue("");
            ed_hhcnrgno.setValue("");
            txt_hhcnrgno.setValue("");
            if (!$c.util.isEmpty(newValue)) {
                scwin.f_PopUp("Consignee", "T");
                scwin.f_CRNLoading(1);
            }
        }
    }
};

scwin.ed_hhscd_onviewchange = function (info) {
    const newValue = info.newValue;
    const oldValue = info.oldValue;

    if (scwin.statusFlag === "C") { // 신규
        if (!$c.util.isEmpty(newValue)) {
            if (oldValue != newValue) {
                txt_hhs1.setValue("");
                scwin.f_PopUp("Shipper", "T");
            }
        }
    } else if (scwin.statusFlag === "U") {  // 수정
        if ($c.util.isEmpty(txt_hhs1.getValue())) {
            txt_hhs1.setValue("");
            if (!$c.util.isEmpty(newValue)) {
                scwin.f_PopUp("Shipper", "T");
            }
        }
    }
};
scwin.ed_hhncd_onviewchange = function (info) {
    if (scwin._copyMode) return;
    const newValue = info.newValue;
    const oldValue = info.oldValue;
    if (scwin.statusFlag === "C" || scwin.statusFlag === "U") { // 신규
        if (oldValue != newValue) {
            txt_hhn1.setValue("");
            if (!$c.util.isEmpty(newValue)) {
                ed_hhntrgno.setValue("");
                txt_hhntrgno.setValue("");

                scwin.f_PopUp('Notify', 'T');
                scwin.f_CRNLoading(2);
            }
        }
    }
};

